const SQL_BY_TAG: Record<string, string> = {
  '0000_wk_baseline':
    "-- WikiKit schema baseline. Embedded in the single binary and applied by the\n-- self-migrator under an advisory lock — never by deployment scripts. Keep\n-- changes additive and create a new migration after release.\n--\n-- Central pattern (atomic apply via wk_apply_proposal): proposal\n-- content is REAL ROWS in the target tables with status='proposed' +\n-- proposal_id — never a JSON diff blob. Approval is a single atomic status\n-- flip inside wk_apply_proposal; rejection keeps every row for audit.\ncreate extension if not exists pgcrypto;\n\n-- ---------------------------------------------------------------------------\n-- wk_spaces — workspace scoping. Multi-space from day one; every space-scoped\n-- query downstream filters by space_id. `epoch` is bumped on every approved\n-- proposal and drives ETag caching on list endpoints.\ncreate table if not exists public.wk_spaces (\n  id uuid primary key default gen_random_uuid(),\n  slug text not null unique check (slug ~ '^[a-z0-9][a-z0-9-]{0,62}$'),\n  name text not null,\n  settings jsonb not null default '{}'::jsonb,\n  epoch bigint not null default 0,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n);\n\n-- ---------------------------------------------------------------------------\n-- wk_sources — original sources archived verbatim. (space_id, content_hash)\n-- is the idempotency anchor: re-ingesting identical content is a 409, never a\n-- duplicate row.\ncreate table if not exists public.wk_sources (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  content_hash text not null,\n  kind text not null check (kind in ('markdown', 'text', 'url', 'import')),\n  url text,\n  title text,\n  raw_content text not null,\n  markdown text not null,\n  metadata jsonb not null default '{}'::jsonb,\n  created_at timestamptz not null default now(),\n  unique (space_id, content_hash)\n);\ncreate index if not exists wk_sources_space_created_idx\n  on public.wk_sources (space_id, created_at desc);\n\n-- ---------------------------------------------------------------------------\n-- wk_concepts — wiki page identity. current_revision_id stays NULL until the\n-- first proposal touching the concept is approved, so concepts with only\n-- proposed revisions are invisible to readers by construction.\ncreate table if not exists public.wk_concepts (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  slug text not null check (slug ~ '^[a-z0-9][a-z0-9-]{0,126}$'),\n  title text not null,\n  current_revision_id uuid,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now(),\n  unique (space_id, slug)\n);\n\n-- ---------------------------------------------------------------------------\n-- wk_concept_revisions — immutable page versions. Rows are never UPDATEd\n-- except for the status flip inside wk_apply_proposal / wk_reject_proposal;\n-- content columns are immutable, which is why the search_vector trigger\n-- (migration 0001) fires on INSERT only. base_revision_id records what the\n-- revision was synthesized against — the stale-base detection anchor.\ncreate table if not exists public.wk_concept_revisions (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  concept_id uuid not null references public.wk_concepts(id) on delete cascade,\n  rev integer not null,\n  status text not null default 'proposed'\n    check (status in ('proposed', 'current', 'superseded', 'rejected')),\n  title text not null,\n  summary text not null default '',\n  markdown text not null,\n  base_revision_id uuid references public.wk_concept_revisions(id),\n  agent_meta jsonb not null default '{}'::jsonb,\n  proposal_id uuid,\n  search_vector tsvector,\n  created_at timestamptz not null default now(),\n  unique (concept_id, rev)\n);\n\nalter table public.wk_concepts\n  drop constraint if exists wk_concepts_current_revision_fk;\nalter table public.wk_concepts\n  add constraint wk_concepts_current_revision_fk\n  foreign key (current_revision_id) references public.wk_concept_revisions(id);\n\ncreate index if not exists wk_concept_revisions_search_idx\n  on public.wk_concept_revisions using gin (search_vector);\ncreate index if not exists wk_concept_revisions_proposal_idx\n  on public.wk_concept_revisions (proposal_id);\n\n-- ---------------------------------------------------------------------------\n-- wk_claims — verifiable statements. The (space_id, subject, predicate) index\n-- is the exact-frame contradiction matcher's backbone: same frame, different\n-- object = dispute.\ncreate table if not exists public.wk_claims (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  concept_id uuid not null references public.wk_concepts(id) on delete cascade,\n  subject text not null,\n  predicate text not null,\n  object text not null,\n  status text not null default 'proposed'\n    check (status in ('proposed', 'draft', 'verified', 'disputed', 'deprecated')),\n  confidence real not null default 0.5 check (confidence >= 0 and confidence <= 1),\n  valid_from timestamptz,\n  valid_until timestamptz,\n  proposal_id uuid,\n  agent_meta jsonb not null default '{}'::jsonb,\n  search_vector tsvector,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n);\ncreate index if not exists wk_claims_frame_idx on public.wk_claims (space_id, subject, predicate);\ncreate index if not exists wk_claims_concept_idx on public.wk_claims (concept_id, status);\ncreate index if not exists wk_claims_search_idx on public.wk_claims using gin (search_vector);\n\n-- ---------------------------------------------------------------------------\n-- wk_citations — provenance per claim. ON DELETE RESTRICT on source_id: a\n-- source that backs a claim can never silently vanish.\ncreate table if not exists public.wk_citations (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  claim_id uuid not null references public.wk_claims(id) on delete cascade,\n  source_id uuid not null references public.wk_sources(id) on delete restrict,\n  quote text not null,\n  locator text not null default '',\n  created_at timestamptz not null default now()\n);\ncreate index if not exists wk_citations_claim_idx on public.wk_citations (claim_id);\n\n-- ---------------------------------------------------------------------------\n-- wk_relations — typed concept links. The unique constraint makes\n-- 'contradicts' relation upserts inside wk_apply_proposal idempotent.\ncreate table if not exists public.wk_relations (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  from_concept_id uuid not null references public.wk_concepts(id) on delete cascade,\n  to_concept_id uuid not null references public.wk_concepts(id) on delete cascade,\n  kind text not null check (kind in ('related', 'part_of', 'depends_on', 'contradicts', 'supersedes')),\n  status text not null default 'proposed' check (status in ('proposed', 'active', 'removed')),\n  proposal_id uuid,\n  created_at timestamptz not null default now(),\n  unique (space_id, from_concept_id, to_concept_id, kind)\n);\n\n-- ---------------------------------------------------------------------------\n-- wk_decisions — decision records (context, rationale, alternatives).\ncreate table if not exists public.wk_decisions (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  slug text not null check (slug ~ '^[a-z0-9][a-z0-9-]{0,126}$'),\n  title text not null,\n  context text not null,\n  decision text not null,\n  rationale text not null default '',\n  alternatives jsonb not null default '[]'::jsonb,\n  status text not null default 'proposed' check (status in ('proposed', 'active', 'superseded')),\n  proposal_id uuid,\n  agent_meta jsonb not null default '{}'::jsonb,\n  created_at timestamptz not null default now(),\n  unique (space_id, slug)\n);\n\n-- ---------------------------------------------------------------------------\n-- wk_change_proposals — the review gate. The partial unique index dedups\n-- pending proposals per (space, input_hash): retrying an identical ingest\n-- converges on the same pending proposal instead of stacking duplicates.\ncreate table if not exists public.wk_change_proposals (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  status text not null default 'pending'\n    check (status in ('pending', 'approved', 'rejected', 'failed')),\n  title text not null,\n  summary text not null default '',\n  input_hash text not null,\n  source_ids uuid[] not null default '{}',\n  agent_meta jsonb not null default '{}'::jsonb,\n  reviewer text,\n  review_note text,\n  reviewed_at timestamptz,\n  created_at timestamptz not null default now()\n);\ncreate unique index if not exists wk_change_proposals_pending_dedup\n  on public.wk_change_proposals (space_id, input_hash) where status = 'pending';\n\n-- Deferred proposal FKs (circular with the staging tables above). ON DELETE\n-- SET NULL: deleting a proposal never cascades into knowledge rows.\nalter table public.wk_concept_revisions\n  drop constraint if exists wk_concept_revisions_proposal_fk;\nalter table public.wk_concept_revisions\n  add constraint wk_concept_revisions_proposal_fk\n  foreign key (proposal_id) references public.wk_change_proposals(id) on delete set null;\n\nalter table public.wk_claims\n  drop constraint if exists wk_claims_proposal_fk;\nalter table public.wk_claims\n  add constraint wk_claims_proposal_fk\n  foreign key (proposal_id) references public.wk_change_proposals(id) on delete set null;\n\nalter table public.wk_relations\n  drop constraint if exists wk_relations_proposal_fk;\nalter table public.wk_relations\n  add constraint wk_relations_proposal_fk\n  foreign key (proposal_id) references public.wk_change_proposals(id) on delete set null;\n\nalter table public.wk_decisions\n  drop constraint if exists wk_decisions_proposal_fk;\nalter table public.wk_decisions\n  add constraint wk_decisions_proposal_fk\n  foreign key (proposal_id) references public.wk_change_proposals(id) on delete set null;\n\n-- ---------------------------------------------------------------------------\n-- wk_api_keys — scoped keys. key_hash = hex HMAC-SHA256(pepper, full key\n-- string); plaintext is returned exactly once at creation and never stored.\ncreate table if not exists public.wk_api_keys (\n  id uuid primary key default gen_random_uuid(),\n  name text not null,\n  key_hash text not null unique,\n  scopes text[] not null,\n  space_id uuid references public.wk_spaces(id) on delete cascade,\n  created_at timestamptz not null default now(),\n  last_used_at timestamptz,\n  revoked_at timestamptz\n);\n\n-- ---------------------------------------------------------------------------\n-- Webhooks — transactional outbox. Events are inserted in the SAME\n-- transaction as the state change they describe (db.emitEvent / the SQL\n-- functions below); the delivery worker picks up dispatched_at IS NULL.\ncreate table if not exists public.wk_outbox_events (\n  id bigserial primary key,\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  event_type text not null,\n  payload jsonb not null,\n  created_at timestamptz not null default now(),\n  dispatched_at timestamptz\n);\ncreate index if not exists wk_outbox_pending_idx\n  on public.wk_outbox_events (id) where dispatched_at is null;\n\ncreate table if not exists public.wk_webhook_endpoints (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  url text not null,\n  secret text not null,\n  events text[] not null default '{}',\n  active boolean not null default true,\n  failure_count integer not null default 0,\n  disabled_until timestamptz,\n  created_at timestamptz not null default now()\n);\n\ncreate table if not exists public.wk_webhook_deliveries (\n  id uuid primary key default gen_random_uuid(),\n  endpoint_id uuid not null references public.wk_webhook_endpoints(id) on delete cascade,\n  event_id bigint not null references public.wk_outbox_events(id) on delete cascade,\n  status text not null default 'pending'\n    check (status in ('pending', 'delivering', 'delivered', 'failed', 'dead')),\n  attempt integer not null default 0,\n  next_attempt_at timestamptz not null default now(),\n  response_status integer,\n  last_error text,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now()\n);\ncreate index if not exists wk_webhook_deliveries_due_idx\n  on public.wk_webhook_deliveries (next_attempt_at) where status in ('pending', 'failed');\n\n-- ---------------------------------------------------------------------------\n-- wk_ingest_jobs — async ingest status (202 + Location pattern).\ncreate table if not exists public.wk_ingest_jobs (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  status text not null default 'queued' check (status in ('queued', 'running', 'done', 'failed')),\n  input jsonb not null,\n  source_id uuid references public.wk_sources(id),\n  proposal_id uuid references public.wk_change_proposals(id),\n  error jsonb,\n  created_at timestamptz not null default now(),\n  started_at timestamptz,\n  finished_at timestamptz\n);\ncreate index if not exists wk_ingest_jobs_queue_idx\n  on public.wk_ingest_jobs (created_at) where status = 'queued';\n\n-- ---------------------------------------------------------------------------\n-- wk_agent_runs — LLM audit ledger, written for EVERY LLM call. The audit\n-- contract downstream systems consume.\ncreate table if not exists public.wk_agent_runs (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  kind text not null check (kind in ('classify', 'synthesize', 'answer', 'adjudicate')),\n  model text not null,\n  prompt_version text not null,\n  input_hash text not null,\n  usage jsonb not null default '{}'::jsonb,\n  duration_ms integer not null default 0,\n  ingest_job_id uuid references public.wk_ingest_jobs(id) on delete set null,\n  proposal_id uuid references public.wk_change_proposals(id) on delete set null,\n  created_at timestamptz not null default now()\n);\ncreate index if not exists wk_agent_runs_space_idx\n  on public.wk_agent_runs (space_id, created_at desc);\n\n-- ---------------------------------------------------------------------------\n-- updated_at maintenance: a single BEFORE UPDATE trigger instead of relying\n-- on every writer to remember `updated_at = now()`. Applied to every table\n-- that carries the column.\ncreate or replace function public.wk_touch_updated_at()\nreturns trigger\nlanguage plpgsql\nas $$\nbegin\n  new.updated_at := now();\n  return new;\nend;\n$$;\n\ndrop trigger if exists wk_spaces_touch_updated_at on public.wk_spaces;\ncreate trigger wk_spaces_touch_updated_at\n  before update on public.wk_spaces\n  for each row execute function public.wk_touch_updated_at();\n\ndrop trigger if exists wk_concepts_touch_updated_at on public.wk_concepts;\ncreate trigger wk_concepts_touch_updated_at\n  before update on public.wk_concepts\n  for each row execute function public.wk_touch_updated_at();\n\ndrop trigger if exists wk_claims_touch_updated_at on public.wk_claims;\ncreate trigger wk_claims_touch_updated_at\n  before update on public.wk_claims\n  for each row execute function public.wk_touch_updated_at();\n\ndrop trigger if exists wk_webhook_deliveries_touch_updated_at on public.wk_webhook_deliveries;\ncreate trigger wk_webhook_deliveries_touch_updated_at\n  before update on public.wk_webhook_deliveries\n  for each row execute function public.wk_touch_updated_at();\n\n-- ---------------------------------------------------------------------------\n-- wk_apply_proposal — atomic approve; the ONLY write path that promotes\n-- proposed content.\n--\n-- Locking order (deadlock discipline): proposal row first (serializes reviews\n-- of the SAME proposal → second caller sees 'approved' → proposal_not_pending),\n-- then the affected concept rows in id order (serializes concurrent approvals\n-- of DIFFERENT proposals touching the SAME concept → the loser re-reads\n-- current_revision_id after the winner commits and fails the stale-base check).\n--\n-- Errors are raised with the machine code as the exact message\n-- ('proposal_not_found' | 'proposal_not_pending' | 'stale_base') so the caller\n-- maps err.message straight onto the §8 error envelope.\ncreate or replace function public.wk_apply_proposal(p_proposal_id uuid, p_reviewer text, p_note text default null)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  proposal public.wk_change_proposals%rowtype;\n  space_slug text;\n  concept_slugs text[] := '{}';\n  claims_verified integer := 0;\n  claims_disputed integer := 0;\nbegin\n  select * into proposal from wk_change_proposals where id = p_proposal_id for update;\n  if not found then\n    raise exception 'proposal_not_found';\n  end if;\n  if proposal.status <> 'pending' then\n    raise exception 'proposal_not_pending';\n  end if;\n\n  select slug into space_slug from wk_spaces where id = proposal.space_id;\n\n  -- Lock every affected concept row, in id order so two proposals sharing a\n  -- concept subset can never deadlock.\n  perform 1\n  from wk_concepts c\n  where c.id in (\n    select r.concept_id from wk_concept_revisions r where r.proposal_id = p_proposal_id\n  )\n  order by c.id\n  for update;\n\n  -- Stale-base check: every proposed revision must have been synthesized\n  -- against what is STILL the concept's current revision (NULL = new concept,\n  -- matched via IS DISTINCT FROM). Anything else means the base moved under\n  -- the proposal → the reviewer approved a diff that no longer applies.\n  if exists (\n    select 1\n    from wk_concept_revisions r\n    join wk_concepts c on c.id = r.concept_id\n    where r.proposal_id = p_proposal_id\n      and r.status = 'proposed'\n      and c.current_revision_id is distinct from r.base_revision_id\n  ) then\n    raise exception 'stale_base';\n  end if;\n\n  -- Flip 1: previous current revisions of the touched concepts → superseded.\n  update wk_concept_revisions old\n  set status = 'superseded'\n  from wk_concept_revisions fresh\n  join wk_concepts c on c.id = fresh.concept_id\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'proposed'\n    and old.id = c.current_revision_id;\n\n  -- Flip 2: proposed revisions → current.\n  update wk_concept_revisions\n  set status = 'current'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 3: repoint the concept (and mirror the revision title so list\n  -- endpoints never show a stale title).\n  update wk_concepts c\n  set current_revision_id = fresh.id,\n      title = fresh.title,\n      updated_at = now()\n  from wk_concept_revisions fresh\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'current'\n    and c.id = fresh.concept_id;\n\n  -- Flip 4: proposed claims → verified.\n  update wk_claims\n  set status = 'verified'\n  where proposal_id = p_proposal_id and status = 'proposed';\n  get diagnostics claims_verified = row_count;\n\n  -- Flip 5: exact-frame contradictions — a freshly verified claim colliding\n  -- with a pre-existing visible claim on the same (space, subject, predicate)\n  -- but a different object disputes BOTH sides. The status filters are stable\n  -- under the flip itself ({verified,disputed} on either side), so the pair\n  -- set is identical when recomputed for the relation insert below.\n  with pairs as (\n    select fresh.id as fresh_id, old.id as old_id\n    from wk_claims fresh\n    join wk_claims old\n      on old.space_id = fresh.space_id\n     and old.subject = fresh.subject\n     and old.predicate = fresh.predicate\n     and old.object <> fresh.object\n    where fresh.proposal_id = p_proposal_id\n      and fresh.status in ('verified', 'disputed')\n      and old.proposal_id is distinct from p_proposal_id\n      and old.status in ('verified', 'disputed')\n  )\n  update wk_claims\n  set status = 'disputed'\n  where status <> 'disputed'\n    and id in (select fresh_id from pairs union select old_id from pairs);\n  get diagnostics claims_disputed = row_count;\n\n  -- Flip 5b: ensure a 'contradicts' relation between the concepts carrying a\n  -- disputed pair. Upsert via the (space, from, to, kind) unique constraint.\n  insert into wk_relations (space_id, from_concept_id, to_concept_id, kind, status, proposal_id)\n  select distinct fresh.space_id, fresh.concept_id, old.concept_id, 'contradicts', 'active', p_proposal_id\n  from wk_claims fresh\n  join wk_claims old\n    on old.space_id = fresh.space_id\n   and old.subject = fresh.subject\n   and old.predicate = fresh.predicate\n   and old.object <> fresh.object\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'disputed'\n    and old.proposal_id is distinct from p_proposal_id\n    and old.status = 'disputed'\n    and fresh.concept_id <> old.concept_id\n  on conflict (space_id, from_concept_id, to_concept_id, kind)\n    do update set status = 'active';\n\n  -- Flip 6: relations and decisions staged by this proposal → active.\n  update wk_relations\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  update wk_decisions\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 7: the proposal itself, plus the space epoch (ETag driver).\n  update wk_change_proposals\n  set status = 'approved', reviewer = p_reviewer, review_note = p_note, reviewed_at = now()\n  where id = p_proposal_id;\n\n  update wk_spaces\n  set epoch = epoch + 1, updated_at = now()\n  where id = proposal.space_id;\n\n  select coalesce(array_agg(distinct c.slug), '{}')\n  into concept_slugs\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id;\n\n  -- Outbox events in the SAME transaction — the transactional-outbox\n  -- guarantee webhooks depend on.\n  insert into wk_outbox_events (space_id, event_type, payload)\n  values (\n    proposal.space_id,\n    'wikikit.proposal.approved',\n    jsonb_build_object(\n      'proposal_id', p_proposal_id,\n      'space', space_slug,\n      'reviewer', p_reviewer,\n      'note', p_note,\n      'concepts', to_jsonb(concept_slugs)\n    )\n  );\n\n  insert into wk_outbox_events (space_id, event_type, payload)\n  select proposal.space_id,\n         'wikikit.concept.updated',\n         jsonb_build_object('space', space_slug, 'slug', c.slug, 'rev', r.rev, 'proposal_id', p_proposal_id)\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id and r.status = 'current';\n\n  return jsonb_build_object(\n    'proposal_id', p_proposal_id,\n    'status', 'approved',\n    'concepts', to_jsonb(concept_slugs),\n    'claims_verified', claims_verified,\n    'claims_disputed', claims_disputed\n  );\nend;\n$$;\n\n-- ---------------------------------------------------------------------------\n-- wk_reject_proposal — atomic reject. Proposed rows KEEP their rows (audit\n-- trail) but become invisible: revisions → 'rejected', relations → 'removed',\n-- claims and decisions stay 'proposed' pinned to the rejected proposal\n-- (readers only ever see verified/disputed/deprecated claims and active\n-- relations/decisions, so nothing leaks).\ncreate or replace function public.wk_reject_proposal(p_proposal_id uuid, p_reviewer text, p_note text default null)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  proposal public.wk_change_proposals%rowtype;\n  space_slug text;\nbegin\n  select * into proposal from wk_change_proposals where id = p_proposal_id for update;\n  if not found then\n    raise exception 'proposal_not_found';\n  end if;\n  if proposal.status <> 'pending' then\n    raise exception 'proposal_not_pending';\n  end if;\n\n  select slug into space_slug from wk_spaces where id = proposal.space_id;\n\n  update wk_concept_revisions\n  set status = 'rejected'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  update wk_relations\n  set status = 'removed'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  update wk_change_proposals\n  set status = 'rejected', reviewer = p_reviewer, review_note = p_note, reviewed_at = now()\n  where id = p_proposal_id;\n\n  insert into wk_outbox_events (space_id, event_type, payload)\n  values (\n    proposal.space_id,\n    'wikikit.proposal.rejected',\n    jsonb_build_object(\n      'proposal_id', p_proposal_id,\n      'space', space_slug,\n      'reviewer', p_reviewer,\n      'note', p_note\n    )\n  );\n\n  return jsonb_build_object('proposal_id', p_proposal_id, 'status', 'rejected');\nend;\n$$;\n",
  '0001_wk_search':
    "-- Server-side full-text search over the knowledge base.\n--   * wk_search_config() pins the text search configuration in ONE place so\n--     the index expressions, the insert triggers and the query side always\n--     stem identically. WikiKit has no per-space locale in v0.1 — 'english'\n--     is the deliberate default (per-space language via wk_spaces.settings is\n--     a v0.2 landing zone; changing the config then requires a backfill\n--     migration, which is why the function is immutable and versioned here).\n--   * wk_concept_revisions.search_vector is filled by a BEFORE INSERT trigger\n--     only — revisions are immutable after insert, so no UPDATE trigger\n--     exists. The frontmatter block is stripped before vectorizing so\n--     structured metadata never pollutes the index.\n--   * wk_claims content (subject/predicate/object) is likewise immutable —\n--     only status flips after insert — so claims also get an INSERT-only\n--     trigger.\n--   * wk_search() joins revisions exclusively over\n--     wk_concepts.current_revision_id and claims over visible statuses:\n--     proposed content is invisible BY CONSTRUCTION, not by filter discipline.\ncreate or replace function public.wk_search_config()\nreturns regconfig\nlanguage sql\nimmutable\nas $$\n  select 'english'::regconfig;\n$$;\n\ncreate or replace function public.wk_revision_search_vector()\nreturns trigger\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  body text;\nbegin\n  body := regexp_replace(new.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '');\n  new.search_vector :=\n       setweight(to_tsvector(public.wk_search_config(), coalesce(new.title, '')), 'A')\n    || setweight(to_tsvector(public.wk_search_config(), coalesce(new.summary, '')), 'B')\n    || setweight(to_tsvector(public.wk_search_config(), body), 'D');\n  return new;\nend;\n$$;\n\ndrop trigger if exists wk_revision_search_vector_insert on public.wk_concept_revisions;\ncreate trigger wk_revision_search_vector_insert\n  before insert on public.wk_concept_revisions\n  for each row execute function public.wk_revision_search_vector();\n\ncreate or replace function public.wk_claim_search_vector()\nreturns trigger\nlanguage plpgsql\nset search_path = public\nas $$\nbegin\n  new.search_vector :=\n       setweight(to_tsvector(public.wk_search_config(), coalesce(new.subject, '')), 'A')\n    || setweight(to_tsvector(public.wk_search_config(), coalesce(new.object, '')), 'B')\n    || setweight(to_tsvector(public.wk_search_config(), coalesce(new.predicate, '')), 'C');\n  return new;\nend;\n$$;\n\ndrop trigger if exists wk_claim_search_vector_insert on public.wk_claims;\ncreate trigger wk_claim_search_vector_insert\n  before insert on public.wk_claims\n  for each row execute function public.wk_claim_search_vector();\n\n-- Backfill any pre-trigger rows (no-op on a fresh database; kept so this\n-- migration is correct even if it ever lands on a database that already has\n-- content — same expressions as the triggers).\nupdate public.wk_concept_revisions\nset search_vector =\n     setweight(to_tsvector(public.wk_search_config(), coalesce(title, '')), 'A')\n  || setweight(to_tsvector(public.wk_search_config(), coalesce(summary, '')), 'B')\n  || setweight(to_tsvector(public.wk_search_config(), regexp_replace(markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')), 'D')\nwhere search_vector is null;\n\nupdate public.wk_claims\nset search_vector =\n     setweight(to_tsvector(public.wk_search_config(), coalesce(subject, '')), 'A')\n  || setweight(to_tsvector(public.wk_search_config(), coalesce(object, '')), 'B')\n  || setweight(to_tsvector(public.wk_search_config(), coalesce(predicate, '')), 'C')\nwhere search_vector is null;\n\n-- wk_search — ranked FTS over current revisions + visible claims.\n-- p_kind: NULL (both) | 'concept' | 'claim'. ts_headline is expensive, so it\n-- runs in a second step over the returned page only.\ncreate or replace function public.wk_search(\n  p_space_id uuid,\n  p_query text,\n  p_kind text default null,\n  p_limit int default 20\n)\nreturns table (\n  kind text,\n  concept_slug text,\n  claim_id uuid,\n  title text,\n  headline text,\n  rank real\n)\nlanguage sql\nstable\nset search_path = public\nas $$\n  with query as (\n    select websearch_to_tsquery(public.wk_search_config(), p_query) as ts\n  ),\n  concept_hits as (\n    select 'concept'::text as kind,\n           c.slug as concept_slug,\n           null::uuid as claim_id,\n           r.title as title,\n           (r.title || E'\\n' || r.summary || E'\\n' ||\n            regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')) as doc,\n           ts_rank(r.search_vector, query.ts)::real as rank,\n           query.ts as ts\n    from wk_concepts c\n    join wk_concept_revisions r on r.id = c.current_revision_id\n    cross join query\n    where c.space_id = p_space_id\n      and (p_kind is null or p_kind = 'concept')\n      and r.search_vector @@ query.ts\n  ),\n  claim_hits as (\n    select 'claim'::text as kind,\n           c.slug as concept_slug,\n           cl.id as claim_id,\n           (cl.subject || ' ' || cl.predicate || ' ' || cl.object) as title,\n           (cl.subject || ' ' || cl.predicate || ' ' || cl.object) as doc,\n           ts_rank(cl.search_vector, query.ts)::real as rank,\n           query.ts as ts\n    from wk_claims cl\n    join wk_concepts c on c.id = cl.concept_id\n    cross join query\n    where cl.space_id = p_space_id\n      and cl.status in ('verified', 'disputed', 'deprecated')\n      and (p_kind is null or p_kind = 'claim')\n      and cl.search_vector @@ query.ts\n  ),\n  hits as (\n    select * from concept_hits\n    union all\n    select * from claim_hits\n    order by rank desc\n    limit p_limit\n  )\n  select hits.kind,\n         hits.concept_slug,\n         hits.claim_id,\n         hits.title,\n         ts_headline(\n           public.wk_search_config(),\n           hits.doc,\n           hits.ts,\n           'StartSel=<mark>,StopSel=</mark>,MaxWords=30'\n         ) as headline,\n         hits.rank\n  from hits\n  order by hits.rank desc;\n$$;\n",
  '0002_wk_distill':
    "-- Session distillation (distill.v1) is a fourth kind of LLM call, so the audit\n-- ledger's kind whitelist has to admit it. The ledger is the audit contract:\n-- every LLM call WikiKit makes lands here, and a call whose kind the CHECK\n-- rejects would fail the write rather than go unrecorded — which is the right\n-- failure mode, and why this constraint moves in lockstep with the provider\n-- interface instead of being loosened to free text.\nalter table public.wk_agent_runs\n  drop constraint if exists wk_agent_runs_kind_check;\n\nalter table public.wk_agent_runs\n  add constraint wk_agent_runs_kind_check\n  check (kind in ('classify', 'synthesize', 'answer', 'distill', 'adjudicate'));\n",
  '0003_wk_operational_integrity':
    "-- Operational-integrity follow-up: durable ingest leases, domain-aware\n-- contradiction semantics, migration-reference hygiene and exact-slug search.\n\nalter table public.wk_ingest_jobs\n  add column if not exists heartbeat_at timestamptz,\n  add column if not exists lease_owner text,\n  add column if not exists lease_expires_at timestamptz;\n\nupdate public.wk_ingest_jobs\nset heartbeat_at = coalesce(heartbeat_at, started_at),\n    lease_expires_at = coalesce(lease_expires_at, started_at + interval '15 minutes')\nwhere status = 'running';\n\ncreate index if not exists wk_ingest_jobs_expired_lease_idx\n  on public.wk_ingest_jobs (lease_expires_at)\n  where status = 'running';\n\n-- Predicate cardinality is domain configuration, never inferred from a vague\n-- predicate name. No declaration means multi-valued.\ncreate or replace function public.wk_functional_predicates(p_space_id uuid)\nreturns text[]\nlanguage sql\nstable\nset search_path = public\nas $$\n  select coalesce(array_agg(item.value), '{}'::text[])\n  from wk_spaces s\n  cross join lateral jsonb_array_elements_text(\n    case\n      when jsonb_typeof(s.settings->'functional_predicates') = 'array'\n        then s.settings->'functional_predicates'\n      else '[]'::jsonb\n    end\n  ) as item(value)\n  where s.id = p_space_id;\n$$;\n\n-- Remove only relations whose exact shape proves they were synthesized by the\n-- old apply-time matcher from a now-multi-valued frame. Preserve a relation\n-- whenever any declared-functional collision still supports it.\nupdate public.wk_relations rel\nset status = 'removed'\nwhere rel.kind = 'contradicts'\n  and rel.status = 'active'\n  and rel.proposal_id is not null\n  and exists (\n    select 1\n    from wk_claims fresh\n    join wk_claims old\n      on old.space_id = fresh.space_id\n     and old.subject = fresh.subject\n     and old.predicate = fresh.predicate\n     and old.object <> fresh.object\n    where fresh.proposal_id = rel.proposal_id\n      and fresh.concept_id = rel.from_concept_id\n      and old.concept_id = rel.to_concept_id\n      and not (fresh.predicate = any(public.wk_functional_predicates(fresh.space_id)))\n  )\n  and not exists (\n    select 1\n    from wk_claims a\n    join wk_claims b\n      on b.space_id = a.space_id\n     and b.subject = a.subject\n     and b.predicate = a.predicate\n     and b.object <> a.object\n    where a.space_id = rel.space_id\n      and a.concept_id = rel.from_concept_id\n      and b.concept_id = rel.to_concept_id\n      and a.status in ('verified', 'disputed')\n      and b.status in ('verified', 'disputed')\n      and a.predicate = any(public.wk_functional_predicates(a.space_id))\n  );\n\nupdate public.wk_claims cl\nset status = 'verified'\nwhere cl.status = 'disputed'\n  and not (cl.predicate = any(public.wk_functional_predicates(cl.space_id)));\n\n-- Migrated domain pages that have no graph edge are attached to their visible\n-- domain root. This is deterministic, idempotent and limited to the migration\n-- marker; no content or claims are fabricated.\ninsert into public.wk_relations (\n  space_id, from_concept_id, to_concept_id, kind, status, proposal_id\n)\nselect s.id, root.id, orphan.id, 'related', 'active', null\nfrom wk_spaces s\njoin wk_concepts root\n  on root.space_id = s.id\n and root.slug = s.slug\n and root.current_revision_id is not null\njoin wk_concepts orphan\n  on orphan.space_id = s.id\n and orphan.current_revision_id is not null\n and orphan.id <> root.id\nwhere s.settings->>'migration' = 'subkit-domain-v1'\n  and not exists (\n    select 1\n    from wk_relations rel\n    where rel.status = 'active'\n      and (rel.from_concept_id = orphan.id or rel.to_concept_id = orphan.id)\n  )\non conflict (space_id, from_concept_id, to_concept_id, kind)\ndo update set status = 'active';\n\n-- The Supabase migration has no concept whose slug equals the space slug.\n-- Use explicit, semantically close anchors rather than a fuzzy title match.\ninsert into public.wk_relations (\n  space_id, from_concept_id, to_concept_id, kind, status, proposal_id\n)\nselect s.id, anchor.id, target.id, 'related', 'active', null\nfrom (\n  values\n    ('supabase-content-type-rewriting', 'supabase-edge-functions'),\n    ('supabase-edge-functions-common-pitfalls', 'supabase-edge-functions'),\n    ('supabase-edge-functions-mechanics', 'supabase-edge-functions'),\n    ('supabase-xhtml-deployment', 'supabase-storage-static-hosting')\n) as link(target_slug, anchor_slug)\njoin wk_spaces s on s.slug = 'supabase' and s.settings->>'migration' = 'subkit-domain-v1'\njoin wk_concepts anchor\n  on anchor.space_id = s.id and anchor.slug = link.anchor_slug and anchor.current_revision_id is not null\njoin wk_concepts target\n  on target.space_id = s.id and target.slug = link.target_slug and target.current_revision_id is not null\non conflict (space_id, from_concept_id, to_concept_id, kind)\ndo update set status = 'active';\n\nupdate public.wk_spaces s\nset epoch = epoch + 1\nwhere s.settings->>'migration' = 'subkit-domain-v1';\n\ncreate or replace function public.wk_apply_proposal(p_proposal_id uuid, p_reviewer text, p_note text default null)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  proposal public.wk_change_proposals%rowtype;\n  space_slug text;\n  concept_slugs text[] := '{}';\n  claims_verified integer := 0;\n  claims_disputed integer := 0;\nbegin\n  select * into proposal from wk_change_proposals where id = p_proposal_id for update;\n  if not found then\n    raise exception 'proposal_not_found';\n  end if;\n  if proposal.status <> 'pending' then\n    raise exception 'proposal_not_pending';\n  end if;\n\n  select slug into space_slug from wk_spaces where id = proposal.space_id;\n\n  -- Lock every affected concept row, in id order so two proposals sharing a\n  -- concept subset can never deadlock.\n  perform 1\n  from wk_concepts c\n  where c.id in (\n    select r.concept_id from wk_concept_revisions r where r.proposal_id = p_proposal_id\n  )\n  order by c.id\n  for update;\n\n  -- Stale-base check: every proposed revision must have been synthesized\n  -- against what is STILL the concept's current revision (NULL = new concept,\n  -- matched via IS DISTINCT FROM). Anything else means the base moved under\n  -- the proposal → the reviewer approved a diff that no longer applies.\n  if exists (\n    select 1\n    from wk_concept_revisions r\n    join wk_concepts c on c.id = r.concept_id\n    where r.proposal_id = p_proposal_id\n      and r.status = 'proposed'\n      and c.current_revision_id is distinct from r.base_revision_id\n  ) then\n    raise exception 'stale_base';\n  end if;\n\n  -- Flip 1: previous current revisions of the touched concepts → superseded.\n  update wk_concept_revisions old\n  set status = 'superseded'\n  from wk_concept_revisions fresh\n  join wk_concepts c on c.id = fresh.concept_id\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'proposed'\n    and old.id = c.current_revision_id;\n\n  -- Flip 2: proposed revisions → current.\n  update wk_concept_revisions\n  set status = 'current'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 3: repoint the concept (and mirror the revision title so list\n  -- endpoints never show a stale title).\n  update wk_concepts c\n  set current_revision_id = fresh.id,\n      title = fresh.title,\n      updated_at = now()\n  from wk_concept_revisions fresh\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'current'\n    and c.id = fresh.concept_id;\n\n  -- Flip 4: proposed claims → verified.\n  update wk_claims\n  set status = 'verified'\n  where proposal_id = p_proposal_id and status = 'proposed';\n  get diagnostics claims_verified = row_count;\n\n  -- Flip 5: only predicates explicitly declared functional for this space\n  -- with a pre-existing visible claim on the same (space, subject, predicate)\n  -- but a different object disputes BOTH sides. The status filters are stable\n  -- under the flip itself ({verified,disputed} on either side), so the pair\n  -- set is identical when recomputed for the relation insert below.\n  with pairs as (\n    select fresh.id as fresh_id, old.id as old_id\n    from wk_claims fresh\n    join wk_claims old\n      on old.space_id = fresh.space_id\n     and old.subject = fresh.subject\n     and old.predicate = fresh.predicate\n     and old.object <> fresh.object\n    where fresh.proposal_id = p_proposal_id\n      and fresh.predicate = any(public.wk_functional_predicates(fresh.space_id))\n      and fresh.status in ('verified', 'disputed')\n      and old.proposal_id is distinct from p_proposal_id\n      and old.status in ('verified', 'disputed')\n  )\n  update wk_claims\n  set status = 'disputed'\n  where status <> 'disputed'\n    and id in (select fresh_id from pairs union select old_id from pairs);\n  get diagnostics claims_disputed = row_count;\n\n  -- Flip 5b: ensure a 'contradicts' relation between the concepts carrying a\n  -- disputed pair. Upsert via the (space, from, to, kind) unique constraint.\n  insert into wk_relations (space_id, from_concept_id, to_concept_id, kind, status, proposal_id)\n  select distinct fresh.space_id, fresh.concept_id, old.concept_id, 'contradicts', 'active', p_proposal_id\n  from wk_claims fresh\n  join wk_claims old\n    on old.space_id = fresh.space_id\n   and old.subject = fresh.subject\n   and old.predicate = fresh.predicate\n   and old.object <> fresh.object\n  where fresh.proposal_id = p_proposal_id\n    and fresh.predicate = any(public.wk_functional_predicates(fresh.space_id))\n    and fresh.status = 'disputed'\n    and old.proposal_id is distinct from p_proposal_id\n    and old.status = 'disputed'\n    and fresh.concept_id <> old.concept_id\n  on conflict (space_id, from_concept_id, to_concept_id, kind)\n    do update set status = 'active';\n\n  -- Flip 6: relations and decisions staged by this proposal → active.\n  update wk_relations\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  update wk_decisions\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 7: the proposal itself, plus the space epoch (ETag driver).\n  update wk_change_proposals\n  set status = 'approved', reviewer = p_reviewer, review_note = p_note, reviewed_at = now()\n  where id = p_proposal_id;\n\n  update wk_spaces\n  set epoch = epoch + 1, updated_at = now()\n  where id = proposal.space_id;\n\n  select coalesce(array_agg(distinct c.slug), '{}')\n  into concept_slugs\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id;\n\n  -- Outbox events in the SAME transaction — the transactional-outbox\n  -- guarantee webhooks depend on.\n  insert into wk_outbox_events (space_id, event_type, payload)\n  values (\n    proposal.space_id,\n    'wikikit.proposal.approved',\n    jsonb_build_object(\n      'proposal_id', p_proposal_id,\n      'space', space_slug,\n      'reviewer', p_reviewer,\n      'note', p_note,\n      'concepts', to_jsonb(concept_slugs)\n    )\n  );\n\n  insert into wk_outbox_events (space_id, event_type, payload)\n  select proposal.space_id,\n         'wikikit.concept.updated',\n         jsonb_build_object('space', space_slug, 'slug', c.slug, 'rev', r.rev, 'proposal_id', p_proposal_id)\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id and r.status = 'current';\n\n  return jsonb_build_object(\n    'proposal_id', p_proposal_id,\n    'status', 'approved',\n    'concepts', to_jsonb(concept_slugs),\n    'claims_verified', claims_verified,\n    'claims_disputed', claims_disputed\n  );\nend;\n$$;\n\n-- Exact slug lookup bypasses websearch hyphen operators and receives a stable\n-- rank boost. Existing vectors were inspected in PROD and are populated; the\n-- derived-column backfill remains defensive for any older/null row.\nupdate public.wk_concept_revisions\nset search_vector =\n     setweight(to_tsvector(public.wk_search_config(), coalesce(title, '')), 'A')\n  || setweight(to_tsvector(public.wk_search_config(), coalesce(summary, '')), 'B')\n  || setweight(to_tsvector(public.wk_search_config(), regexp_replace(markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')), 'D')\nwhere search_vector is null;\n\ncreate or replace function public.wk_search(p_space_id uuid,\n  p_query text,\n  p_kind text default null,\n  p_limit int default 20\n)\nreturns table (\n  kind text,\n  concept_slug text,\n  claim_id uuid,\n  title text,\n  headline text,\n  rank real\n)\nlanguage sql\nstable\nset search_path = public\nas $$\n  with query as (\n    select websearch_to_tsquery(public.wk_search_config(), p_query) as ts\n  ),\n  concept_hits as (\n    select 'concept'::text as kind,\n           c.slug as concept_slug,\n           null::uuid as claim_id,\n           r.title as title,\n           (r.title || E'\\n' || r.summary || E'\\n' ||\n            regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')) as doc,\n           (case when lower(c.slug) = lower(btrim(p_query)) then 10.0 else ts_rank(r.search_vector, query.ts) end)::real as rank,\n           query.ts as ts\n    from wk_concepts c\n    join wk_concept_revisions r on r.id = c.current_revision_id\n    cross join query\n    where c.space_id = p_space_id\n      and (p_kind is null or p_kind = 'concept')\n      and (r.search_vector @@ query.ts or lower(c.slug) = lower(btrim(p_query)))\n  ),\n  claim_hits as (\n    select 'claim'::text as kind,\n           c.slug as concept_slug,\n           cl.id as claim_id,\n           (cl.subject || ' ' || cl.predicate || ' ' || cl.object) as title,\n           (cl.subject || ' ' || cl.predicate || ' ' || cl.object) as doc,\n           ts_rank(cl.search_vector, query.ts)::real as rank,\n           query.ts as ts\n    from wk_claims cl\n    join wk_concepts c on c.id = cl.concept_id\n    cross join query\n    where cl.space_id = p_space_id\n      and cl.status in ('verified', 'disputed', 'deprecated')\n      and (p_kind is null or p_kind = 'claim')\n      and cl.search_vector @@ query.ts\n  ),\n  hits as (\n    select * from concept_hits\n    union all\n    select * from claim_hits\n    order by rank desc\n    limit p_limit\n  )\n  select hits.kind,\n         hits.concept_slug,\n         hits.claim_id,\n         hits.title,\n         ts_headline(\n           public.wk_search_config(),\n           hits.doc,\n           hits.ts,\n           'StartSel=<mark>,StopSel=</mark>,MaxWords=30'\n         ) as headline,\n         hits.rank\n  from hits\n  order by hits.rank desc;\n$$;\n",
  '0004_wk_mcp_oauth':
    "-- OAuth 2.1 authorization server for remote MCP clients such as ChatGPT.\n--\n-- API keys remain WikiKit's operator credential. The authorization endpoint\n-- validates one without persisting its plaintext, then issues short-lived,\n-- scoped OAuth tokens. Codes and tokens are stored only as peppered HMACs,\n-- exactly like wk_api_keys.\n\ncreate table if not exists public.wk_oauth_clients (\n  client_id text primary key,\n  client_name text not null default 'MCP client',\n  redirect_uris text[] not null,\n  token_endpoint_auth_method text not null default 'none'\n    check (token_endpoint_auth_method = 'none'),\n  created_at timestamptz not null default now(),\n  revoked_at timestamptz\n);\n\ncreate table if not exists public.wk_oauth_authorization_codes (\n  id uuid primary key default gen_random_uuid(),\n  code_hash text not null unique,\n  client_id text not null references public.wk_oauth_clients(client_id) on delete cascade,\n  redirect_uri text not null,\n  scopes text[] not null,\n  code_challenge text not null,\n  resource text not null,\n  principal_name text not null,\n  principal_space_id uuid references public.wk_spaces(id) on delete cascade,\n  principal_key_id text not null,\n  principal_key_hash text not null,\n  expires_at timestamptz not null,\n  consumed_at timestamptz,\n  created_at timestamptz not null default now()\n);\ncreate index if not exists wk_oauth_codes_expiry_idx\n  on public.wk_oauth_authorization_codes (expires_at)\n  where consumed_at is null;\n\ncreate table if not exists public.wk_oauth_access_tokens (\n  id uuid primary key default gen_random_uuid(),\n  token_hash text not null unique,\n  client_id text not null references public.wk_oauth_clients(client_id) on delete cascade,\n  scopes text[] not null,\n  resource text not null,\n  principal_name text not null,\n  principal_space_id uuid references public.wk_spaces(id) on delete cascade,\n  principal_key_id text not null,\n  principal_key_hash text not null,\n  family_id uuid not null,\n  expires_at timestamptz not null,\n  revoked_at timestamptz,\n  last_used_at timestamptz,\n  created_at timestamptz not null default now()\n);\ncreate index if not exists wk_oauth_access_expiry_idx\n  on public.wk_oauth_access_tokens (expires_at)\n  where revoked_at is null;\ncreate index if not exists wk_oauth_access_family_idx\n  on public.wk_oauth_access_tokens (family_id);\n\ncreate table if not exists public.wk_oauth_refresh_tokens (\n  id uuid primary key default gen_random_uuid(),\n  token_hash text not null unique,\n  client_id text not null references public.wk_oauth_clients(client_id) on delete cascade,\n  scopes text[] not null,\n  resource text not null,\n  principal_name text not null,\n  principal_space_id uuid references public.wk_spaces(id) on delete cascade,\n  principal_key_id text not null,\n  principal_key_hash text not null,\n  family_id uuid not null,\n  expires_at timestamptz not null,\n  revoked_at timestamptz,\n  created_at timestamptz not null default now()\n);\ncreate index if not exists wk_oauth_refresh_expiry_idx\n  on public.wk_oauth_refresh_tokens (expires_at)\n  where revoked_at is null;\ncreate index if not exists wk_oauth_refresh_family_idx\n  on public.wk_oauth_refresh_tokens (family_id);\n",
  '0005_wk_oauth_external_identity':
    "-- External identities are OAuth-login principals, never API keys. Provider\n-- ids are opaque deployment slugs; revocation invalidates grants without\n-- exposing a shared credential or introducing a provider-specific schema.\ncreate table if not exists public.wk_oauth_identities (\n  provider_subject text not null,\n  email text not null,\n  provider text not null check (provider ~ '^[a-z0-9][a-z0-9-]{0,62}$'),\n  created_at timestamptz not null default now(),\n  last_seen_at timestamptz not null default now(),\n  revoked_at timestamptz,\n  primary key (provider, provider_subject)\n);\n\ncreate table if not exists public.wk_oauth_login_states (\n  id uuid primary key default gen_random_uuid(),\n  state_hash text not null unique,\n  client_id text not null references public.wk_oauth_clients(client_id) on delete cascade,\n  redirect_uri text not null,\n  scopes text[] not null,\n  code_challenge text not null,\n  resource text not null,\n  client_state text,\n  provider_id text,\n  provider_subject text,\n  provider_email text,\n  oidc_nonce text,\n  oidc_code_verifier text,\n  authenticated_at timestamptz,\n  expires_at timestamptz not null,\n  consumed_at timestamptz,\n  created_at timestamptz not null default now()\n);\ncreate index if not exists wk_oauth_login_states_expiry_idx\n  on public.wk_oauth_login_states (expires_at)\n  where consumed_at is null;\n\nalter table public.wk_oauth_authorization_codes\n  add column if not exists principal_kind text not null default 'api_key'\n    check (principal_kind in ('api_key', 'identity'));\nalter table public.wk_oauth_access_tokens\n  add column if not exists principal_kind text not null default 'api_key'\n    check (principal_kind in ('api_key', 'identity'));\nalter table public.wk_oauth_refresh_tokens\n  add column if not exists principal_kind text not null default 'api_key'\n    check (principal_kind in ('api_key', 'identity'));\n",
  '0006_wk_oauth_provider_metadata':
    "-- Keep provider metadata structural and uniformly indexed. The columns are\n-- repeated with IF NOT EXISTS so this step is safe after a partially completed\n-- bootstrap without introducing an alternate schema shape.\nalter table public.wk_oauth_login_states\n  add column if not exists provider_id text,\n  add column if not exists oidc_nonce text,\n  add column if not exists oidc_code_verifier text;\n\nalter table public.wk_oauth_identities\n  drop constraint if exists wk_oauth_identities_provider_check;\nalter table public.wk_oauth_identities\n  add constraint wk_oauth_identities_provider_check\n    check (provider ~ '^[a-z0-9][a-z0-9-]{0,62}$');\n\ncreate index if not exists wk_oauth_identities_provider_active_idx\n  on public.wk_oauth_identities (provider, last_seen_at desc)\n  where revoked_at is null;\n",
  '0007_wk_product_stats':
    "-- Time-leading, space-scoped indexes for the product analytics API. The API\n-- aggregates WikiKit's own tables at read time; no cross-product database\n-- access and no consumer-specific reporting tables are introduced.\ncreate index if not exists wk_ingest_jobs_space_created_idx\n  on public.wk_ingest_jobs (space_id, created_at);\ncreate index if not exists wk_concepts_space_created_idx\n  on public.wk_concepts (space_id, created_at);\ncreate index if not exists wk_concept_revisions_space_created_idx\n  on public.wk_concept_revisions (space_id, created_at);\ncreate index if not exists wk_claims_space_created_idx\n  on public.wk_claims (space_id, created_at);\ncreate index if not exists wk_citations_space_created_idx\n  on public.wk_citations (space_id, created_at);\ncreate index if not exists wk_decisions_space_created_idx\n  on public.wk_decisions (space_id, created_at);\ncreate index if not exists wk_change_proposals_space_created_idx\n  on public.wk_change_proposals (space_id, created_at);\ncreate index if not exists wk_change_proposals_space_reviewed_idx\n  on public.wk_change_proposals (space_id, reviewed_at)\n  where reviewed_at is not null;\ncreate index if not exists wk_outbox_events_space_created_idx\n  on public.wk_outbox_events (space_id, created_at);\ncreate index if not exists wk_webhook_endpoints_space_idx\n  on public.wk_webhook_endpoints (space_id, id);\ncreate index if not exists wk_webhook_deliveries_endpoint_created_idx\n  on public.wk_webhook_deliveries (endpoint_id, created_at);\n",
  '0008_wk_ingest_quota_backoff':
    "-- Provider quota exhaustion must pause ingest, not fail it: a burst of jobs\n-- hitting \"You have reached your specified API usage limits\" was flipped to\n-- failed and the work lost until a human re-submitted — days after the quota\n-- reset. quota_blocked parks the job with a resume_at; the worker requeues it\n-- once the provider window reopens.\n\nalter table public.wk_ingest_jobs\n  drop constraint if exists wk_ingest_jobs_status_check;\nalter table public.wk_ingest_jobs\n  add constraint wk_ingest_jobs_status_check\n    check (status in ('queued', 'running', 'done', 'failed', 'quota_blocked'));\n\nalter table public.wk_ingest_jobs\n  add column if not exists resume_at timestamptz;\n\ncreate index if not exists wk_ingest_jobs_quota_blocked_idx\n  on public.wk_ingest_jobs (resume_at)\n  where status = 'quota_blocked';\n",
  '0009_wk_usage_telemetry':
    "-- Opt-in, privacy-bounded product usage telemetry. Events contain no source\n-- content, prompts, query strings, tool arguments/results, network identifiers,\n-- credentials or dynamic resource ids. Actor/session values are product-local\n-- HMACs computed before the append-only row is written.\ncreate table if not exists public.wk_usage_events (\n  id bigserial primary key,\n  space_id uuid references public.wk_spaces(id) on delete cascade,\n  surface text not null check (surface in ('http', 'mcp', 'knowledge', 'review')),\n  operation text not null check (operation ~ '^[a-z][a-z0-9_.:-]{0,79}$'),\n  route text check (route is null or (length(route) between 1 and 200 and route not like '%?%')),\n  method text check (method is null or method in ('GET', 'HEAD', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS')),\n  status_code integer check (status_code is null or status_code between 100 and 599),\n  outcome text not null check (outcome in ('success', 'client_error', 'server_error', 'rejected', 'timeout', 'cancelled')),\n  traffic_class text not null default 'organic' check (traffic_class in ('organic', 'synthetic', 'internal')),\n  request_source text not null default 'api' check (request_source in ('api', 'gateway', 'scheduler', 'manual', 'mcp')),\n  actor_hmac text check (actor_hmac is null or actor_hmac ~ '^[0-9a-f]{64}$'),\n  session_hmac text check (session_hmac is null or session_hmac ~ '^[0-9a-f]{64}$'),\n  duration_ms bigint not null default 0 check (duration_ms >= 0),\n  request_bytes bigint check (request_bytes is null or request_bytes >= 0),\n  response_bytes bigint check (response_bytes is null or response_bytes >= 0),\n  result_count integer check (result_count is null or result_count >= 0),\n  tool_name text check (tool_name is null or tool_name ~ '^[a-z][a-z0-9_]{0,79}$'),\n  response_mode text check (response_mode is null or response_mode in ('json', 'sse', 'none')),\n  active_sessions integer check (active_sessions is null or active_sessions >= 0),\n  created_at timestamptz not null default now()\n);\n\ncreate index if not exists wk_usage_events_space_created_idx\n  on public.wk_usage_events (space_id, created_at);\ncreate index if not exists wk_usage_events_surface_created_idx\n  on public.wk_usage_events (surface, created_at);\ncreate index if not exists wk_usage_events_space_surface_created_idx\n  on public.wk_usage_events (space_id, surface, created_at);\ncreate index if not exists wk_usage_events_created_idx\n  on public.wk_usage_events (created_at);\n",
  '0010_wk_review_channel':
    "-- Durable provenance for every new terminal proposal review. Existing rows\n-- remain NULL because their historical transport cannot be reconstructed.\nalter table public.wk_change_proposals\n  add column if not exists review_channel text;\n\nalter table public.wk_change_proposals\n  drop constraint if exists wk_change_proposals_review_channel_check;\nalter table public.wk_change_proposals\n  add constraint wk_change_proposals_review_channel_check\n    check (review_channel is null or review_channel in ('rest', 'mcp_elicitation'));\n\n-- Preserve the proven locking/status-flip implementations from the previous\n-- migrations as private cores. The public four-argument wrappers add channel\n-- provenance and enrich the just-created outbox payload in the SAME database\n-- transaction. The default keeps v0.4 binaries and direct three-argument calls\n-- operational during a binary rollback.\nalter function public.wk_apply_proposal(uuid, text, text)\n  rename to wk_apply_proposal_core_0003;\n\ncreate function public.wk_apply_proposal(\n  p_proposal_id uuid,\n  p_reviewer text,\n  p_note text default null,\n  p_review_channel text default 'rest'\n)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  result jsonb;\nbegin\n  if p_review_channel is null or p_review_channel not in ('rest', 'mcp_elicitation') then\n    raise exception 'invalid_review_channel';\n  end if;\n\n  select public.wk_apply_proposal_core_0003(p_proposal_id, p_reviewer, p_note)\n    into result;\n\n  update public.wk_change_proposals\n     set review_channel = p_review_channel\n   where id = p_proposal_id;\n\n  update public.wk_outbox_events\n     set payload = payload || jsonb_build_object('review_channel', p_review_channel)\n   where event_type = 'wikikit.proposal.approved'\n     and payload->>'proposal_id' = p_proposal_id::text;\n\n  return result || jsonb_build_object('review_channel', p_review_channel);\nend;\n$$;\n\nalter function public.wk_reject_proposal(uuid, text, text)\n  rename to wk_reject_proposal_core_0000;\n\ncreate function public.wk_reject_proposal(\n  p_proposal_id uuid,\n  p_reviewer text,\n  p_note text default null,\n  p_review_channel text default 'rest'\n)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  result jsonb;\nbegin\n  if p_review_channel is null or p_review_channel not in ('rest', 'mcp_elicitation') then\n    raise exception 'invalid_review_channel';\n  end if;\n\n  select public.wk_reject_proposal_core_0000(p_proposal_id, p_reviewer, p_note)\n    into result;\n\n  update public.wk_change_proposals\n     set review_channel = p_review_channel\n   where id = p_proposal_id;\n\n  update public.wk_outbox_events\n     set payload = payload || jsonb_build_object('review_channel', p_review_channel)\n   where event_type = 'wikikit.proposal.rejected'\n     and payload->>'proposal_id' = p_proposal_id::text;\n\n  return result || jsonb_build_object('review_channel', p_review_channel);\nend;\n$$;\n",
  '0011_wk_usage_outcome_handoff':
    "-- 'handoff': a review request on a client without form elicitation completed\n-- correctly WITHOUT a mutation — the proposal stays pending for an out-of-band\n-- human review. Counted separately from 'success' so operators can see how\n-- often clients cannot finish the review natively.\nalter table public.wk_usage_events\n  drop constraint if exists wk_usage_events_outcome_check;\nalter table public.wk_usage_events\n  add constraint wk_usage_events_outcome_check\n    check (outcome in ('success', 'client_error', 'server_error', 'rejected', 'timeout', 'cancelled', 'handoff'));\n",
  '0012_wk_oauth_operator_sessions':
    "-- Reusable, revocable browser sessions for MCP OAuth consent. The opaque\n-- browser token is represented only by its keyed hash; source API keys and\n-- external-provider assertions are never persisted here.\ncreate table if not exists public.wk_oauth_operator_sessions (\n  id uuid primary key default gen_random_uuid(),\n  token_hash text not null unique,\n  principal_kind text not null check (principal_kind in ('api_key', 'identity')),\n  principal_key_id text not null,\n  principal_key_hash text not null,\n  principal_name text not null,\n  principal_space_id uuid references public.wk_spaces(id) on delete cascade,\n  provider_id text,\n  provider_subject text,\n  scopes text[] not null,\n  expires_at timestamptz not null,\n  absolute_expires_at timestamptz not null,\n  last_used_at timestamptz not null default now(),\n  revoked_at timestamptz,\n  created_at timestamptz not null default now(),\n  check (\n    (principal_kind = 'api_key' and provider_id is null and provider_subject is null)\n    or\n    (principal_kind = 'identity' and provider_id is not null and provider_subject is not null)\n  )\n);\n\ncreate index if not exists wk_oauth_operator_sessions_expiry_idx\n  on public.wk_oauth_operator_sessions (absolute_expires_at)\n  where revoked_at is null;\n",
  '0013_wk_provider_neutral_identity':
    "-- External identities are represented uniformly regardless of login protocol.\n-- This release intentionally invalidates in-flight external OAuth grants and\n-- browser sessions; users authenticate again through the configured provider.\ndelete from public.wk_oauth_authorization_codes where principal_kind <> 'api_key';\ndelete from public.wk_oauth_access_tokens where principal_kind <> 'api_key';\ndelete from public.wk_oauth_refresh_tokens where principal_kind <> 'api_key';\ndelete from public.wk_oauth_operator_sessions where principal_kind <> 'api_key';\n\nalter table public.wk_oauth_authorization_codes\n  drop constraint if exists wk_oauth_authorization_codes_principal_kind_check;\nalter table public.wk_oauth_authorization_codes\n  add constraint wk_oauth_authorization_codes_principal_kind_check\n    check (principal_kind in ('api_key', 'identity'));\n\nalter table public.wk_oauth_access_tokens\n  drop constraint if exists wk_oauth_access_tokens_principal_kind_check;\nalter table public.wk_oauth_access_tokens\n  add constraint wk_oauth_access_tokens_principal_kind_check\n    check (principal_kind in ('api_key', 'identity'));\n\nalter table public.wk_oauth_refresh_tokens\n  drop constraint if exists wk_oauth_refresh_tokens_principal_kind_check;\nalter table public.wk_oauth_refresh_tokens\n  add constraint wk_oauth_refresh_tokens_principal_kind_check\n    check (principal_kind in ('api_key', 'identity'));\n\nalter table public.wk_oauth_operator_sessions\n  drop constraint if exists wk_oauth_operator_sessions_principal_kind_check;\nalter table public.wk_oauth_operator_sessions\n  drop constraint if exists wk_oauth_operator_sessions_check;\nalter table public.wk_oauth_operator_sessions\n  add constraint wk_oauth_operator_sessions_principal_kind_check\n    check (principal_kind in ('api_key', 'identity'));\nalter table public.wk_oauth_operator_sessions\n  add constraint wk_oauth_operator_sessions_provider_check check (\n    (principal_kind = 'api_key' and provider_id is null and provider_subject is null)\n    or\n    (principal_kind = 'identity' and provider_id is not null and provider_subject is not null)\n  );\n",
  '0014_wk_relation_removals':
    "-- relations_removed: a pending removal is a MARKER (removal_proposal_id) on\n-- the still-ACTIVE wk_relations row — never a status flip before approval,\n-- because every reader filters status = 'active' and the unique\n-- (space_id, from_concept_id, to_concept_id, kind) constraint allows exactly\n-- one row per edge. Approve flips the marked row to 'removed' (soft delete;\n-- the marker is KEPT for the audit trail — rows are never hard-deleted).\n-- Reject touches nothing: the marker stays pinned to the rejected proposal so\n-- its diff remains reviewable after the fact, exactly like rejected claims\n-- and decisions. A later proposal re-staging the same removal overwrites the\n-- marker (single-slot provenance — the same accepted trade-off as\n-- proposal_id re-adoption in createProposal).\nalter table public.wk_relations\n  add column if not exists removal_proposal_id uuid;\n\nalter table public.wk_relations\n  drop constraint if exists wk_relations_removal_proposal_fk;\nalter table public.wk_relations\n  add constraint wk_relations_removal_proposal_fk\n  foreign key (removal_proposal_id) references public.wk_change_proposals(id) on delete set null;\n\ncreate index if not exists wk_relations_removal_proposal_idx\n  on public.wk_relations (removal_proposal_id)\n  where removal_proposal_id is not null;\n\n-- Same-signature redefinition of the apply core (the 0003 precedent: CREATE\n-- OR REPLACE under the existing name — the 0010 four-argument public wrapper\n-- keeps calling wk_apply_proposal_core_0003 unchanged, and the raise messages\n-- stay exactly 'proposal_not_found' / 'proposal_not_pending' / 'stale_base').\n-- Additions over 0003: the concept-lock set also covers removal endpoints,\n-- Flip 6b deactivates marked relations, and the result carries\n-- relations_removed. wk_reject_proposal_core_0000 needs NO change: its\n-- relation flip is guarded status = 'proposed', so marked ACTIVE rows are\n-- untouched by rejection by construction.\ncreate or replace function public.wk_apply_proposal_core_0003(p_proposal_id uuid, p_reviewer text, p_note text default null)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  proposal public.wk_change_proposals%rowtype;\n  space_slug text;\n  concept_slugs text[] := '{}';\n  claims_verified integer := 0;\n  claims_disputed integer := 0;\n  relations_removed_count integer := 0;\nbegin\n  select * into proposal from wk_change_proposals where id = p_proposal_id for update;\n  if not found then\n    raise exception 'proposal_not_found';\n  end if;\n  if proposal.status <> 'pending' then\n    raise exception 'proposal_not_pending';\n  end if;\n\n  select slug into space_slug from wk_spaces where id = proposal.space_id;\n\n  -- Lock every affected concept row, in id order so two proposals sharing a\n  -- concept subset can never deadlock. Now includes the endpoints of\n  -- relations this proposal marks for removal — they may have no staged\n  -- revision of their own.\n  perform 1\n  from wk_concepts c\n  where c.id in (\n    select r.concept_id from wk_concept_revisions r where r.proposal_id = p_proposal_id\n    union\n    select rel.from_concept_id from wk_relations rel where rel.removal_proposal_id = p_proposal_id\n    union\n    select rel.to_concept_id from wk_relations rel where rel.removal_proposal_id = p_proposal_id\n  )\n  order by c.id\n  for update;\n\n  -- Stale-base check: every proposed revision must have been synthesized\n  -- against what is STILL the concept's current revision (NULL = new concept,\n  -- matched via IS DISTINCT FROM). Anything else means the base moved under\n  -- the proposal → the reviewer approved a diff that no longer applies.\n  if exists (\n    select 1\n    from wk_concept_revisions r\n    join wk_concepts c on c.id = r.concept_id\n    where r.proposal_id = p_proposal_id\n      and r.status = 'proposed'\n      and c.current_revision_id is distinct from r.base_revision_id\n  ) then\n    raise exception 'stale_base';\n  end if;\n\n  -- Flip 1: previous current revisions of the touched concepts → superseded.\n  update wk_concept_revisions old\n  set status = 'superseded'\n  from wk_concept_revisions fresh\n  join wk_concepts c on c.id = fresh.concept_id\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'proposed'\n    and old.id = c.current_revision_id;\n\n  -- Flip 2: proposed revisions → current.\n  update wk_concept_revisions\n  set status = 'current'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 3: repoint the concept (and mirror the revision title so list\n  -- endpoints never show a stale title).\n  update wk_concepts c\n  set current_revision_id = fresh.id,\n      title = fresh.title,\n      updated_at = now()\n  from wk_concept_revisions fresh\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'current'\n    and c.id = fresh.concept_id;\n\n  -- Flip 4: proposed claims → verified.\n  update wk_claims\n  set status = 'verified'\n  where proposal_id = p_proposal_id and status = 'proposed';\n  get diagnostics claims_verified = row_count;\n\n  -- Flip 5: only predicates explicitly declared functional for this space\n  -- with a pre-existing visible claim on the same (space, subject, predicate)\n  -- but a different object disputes BOTH sides. The status filters are stable\n  -- under the flip itself ({verified,disputed} on either side), so the pair\n  -- set is identical when recomputed for the relation insert below.\n  with pairs as (\n    select fresh.id as fresh_id, old.id as old_id\n    from wk_claims fresh\n    join wk_claims old\n      on old.space_id = fresh.space_id\n     and old.subject = fresh.subject\n     and old.predicate = fresh.predicate\n     and old.object <> fresh.object\n    where fresh.proposal_id = p_proposal_id\n      and fresh.predicate = any(public.wk_functional_predicates(fresh.space_id))\n      and fresh.status in ('verified', 'disputed')\n      and old.proposal_id is distinct from p_proposal_id\n      and old.status in ('verified', 'disputed')\n  )\n  update wk_claims\n  set status = 'disputed'\n  where status <> 'disputed'\n    and id in (select fresh_id from pairs union select old_id from pairs);\n  get diagnostics claims_disputed = row_count;\n\n  -- Flip 5b: ensure a 'contradicts' relation between the concepts carrying a\n  -- disputed pair. Upsert via the (space, from, to, kind) unique constraint.\n  -- The DO UPDATE also CLEARS any pending removal marker: the apply function\n  -- itself just re-derived this contradiction, which supersedes a staged\n  -- removal of the same edge — otherwise Flip 6b below would deactivate, in\n  -- the same transaction, the very relation Flip 5b asserted, leaving two\n  -- freshly disputed claims without their contradicts signal.\n  insert into wk_relations (space_id, from_concept_id, to_concept_id, kind, status, proposal_id)\n  select distinct fresh.space_id, fresh.concept_id, old.concept_id, 'contradicts', 'active', p_proposal_id\n  from wk_claims fresh\n  join wk_claims old\n    on old.space_id = fresh.space_id\n   and old.subject = fresh.subject\n   and old.predicate = fresh.predicate\n   and old.object <> fresh.object\n  where fresh.proposal_id = p_proposal_id\n    and fresh.predicate = any(public.wk_functional_predicates(fresh.space_id))\n    and fresh.status = 'disputed'\n    and old.proposal_id is distinct from p_proposal_id\n    and old.status = 'disputed'\n    and fresh.concept_id <> old.concept_id\n  on conflict (space_id, from_concept_id, to_concept_id, kind)\n    do update set status = 'active', removal_proposal_id = null;\n\n  -- Flip 6: relations and decisions staged by this proposal → active.\n  update wk_relations\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  update wk_decisions\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 6b: relations MARKED for removal by this proposal → removed. The\n  -- row stayed 'active' (visible to every reader) throughout review; only\n  -- approval deactivates it. removal_proposal_id is kept for the audit\n  -- trail — never hard-deleted. Idempotent under races: a marker stolen by a\n  -- later proposal, or an edge already removed by a concurrently approved\n  -- one, simply matches nothing and the count reports it.\n  update wk_relations\n  set status = 'removed'\n  where removal_proposal_id = p_proposal_id and status = 'active';\n  get diagnostics relations_removed_count = row_count;\n\n  -- Flip 7: the proposal itself, plus the space epoch (ETag driver).\n  update wk_change_proposals\n  set status = 'approved', reviewer = p_reviewer, review_note = p_note, reviewed_at = now()\n  where id = p_proposal_id;\n\n  update wk_spaces\n  set epoch = epoch + 1, updated_at = now()\n  where id = proposal.space_id;\n\n  select coalesce(array_agg(distinct c.slug), '{}')\n  into concept_slugs\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id;\n\n  -- Outbox events in the SAME transaction — the transactional-outbox\n  -- guarantee webhooks depend on.\n  insert into wk_outbox_events (space_id, event_type, payload)\n  values (\n    proposal.space_id,\n    'wikikit.proposal.approved',\n    jsonb_build_object(\n      'proposal_id', p_proposal_id,\n      'space', space_slug,\n      'reviewer', p_reviewer,\n      'note', p_note,\n      'concepts', to_jsonb(concept_slugs)\n    )\n  );\n\n  insert into wk_outbox_events (space_id, event_type, payload)\n  select proposal.space_id,\n         'wikikit.concept.updated',\n         jsonb_build_object('space', space_slug, 'slug', c.slug, 'rev', r.rev, 'proposal_id', p_proposal_id)\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id and r.status = 'current';\n\n  return jsonb_build_object(\n    'proposal_id', p_proposal_id,\n    'status', 'approved',\n    'concepts', to_jsonb(concept_slugs),\n    'claims_verified', claims_verified,\n    'claims_disputed', claims_disputed,\n    'relations_removed', relations_removed_count\n  );\nend;\n$$;\n",
  '0015_wk_optional_identity_email':
    '-- The immutable OIDC subject is the identity anchor. Email is optional and is\n-- persisted only when the provider explicitly marks it as verified.\nalter table public.wk_oauth_identities\n  alter column email drop not null;\n',
  '0016_wk_search_multilingual':
    "-- Multilingual search: per-space (and per-source) text search configuration,\n-- accent-insensitive matching and trigram fallback.\n--\n--   * 0001 pinned 'english' in the immutable wk_search_config() and named\n--     wk_spaces.settings as the v0.2 landing zone for a per-space language.\n--     This migration is that landing zone becoming real:\n--     settings->>'language' ('en' | 'de' | 'simple', default 'en') now\n--     selects the configuration. The superseded wk_search_config() pin is\n--     DROPPED at the end of this migration — no legacy objects.\n--   * wk_english / wk_german are COPIES of the built-in configurations with\n--     unaccent installed as a FILTERING dictionary. Putting unaccent inside\n--     the configuration (instead of unaccent() calls in expressions) applies\n--     it symmetrically to indexing, websearch_to_tsquery and ts_headline,\n--     and sidesteps unaccent()'s STABLE-not-IMMUTABLE problem entirely.\n--   * search_vector stays a STORED trigger-filled column (plain GIN index,\n--     no expression index), so config resolution may be STABLE — the\n--     IMMUTABLE constraint on the 0001 function only existed to keep one\n--     pinned config, not for index correctness.\n--   * Language changes after the fact go through wk_reindex_space(), which\n--     recomputes the derived vectors for one space. Revisions and claims\n--     stay immutable in CONTENT — the derived search_vector is the one\n--     column the 0001/0003 backfills already updated in place.\n--   * pg_trgm adds typo tolerance on concept slugs and revision titles with\n--     fixed, documented constants: similarity >= 0.45 on the slug,\n--     word_similarity >= 0.6 on the title; trigram rank contributions are\n--     5.0 * slug-similarity and 3.0 * title-word-similarity, so a trigram\n--     match outranks plain text hits (ts_rank rarely exceeds 1.0) but never\n--     the exact-slug boost (10.0). Deterministic and explainable by design.\n--   * The final backfill re-vectorizes EVERY revision and claim (not just\n--     null vectors): existing 'english'-stemmed vectors must be restemmed\n--     under the new per-space configuration, and unaccent must apply to\n--     spaces that stay English.\ncreate extension if not exists unaccent;\n\ncreate extension if not exists pg_trgm;\n\n-- Text search configurations are not idempotent to create — guard on\n-- pg_ts_config so the migration is safe on a dirty dev database.\ndo $do$\nbegin\n  if not exists (\n    select 1 from pg_ts_config c join pg_namespace n on n.oid = c.cfgnamespace\n    where c.cfgname = 'wk_english' and n.nspname = 'public'\n  ) then\n    execute 'create text search configuration public.wk_english (copy = english)';\n    execute 'alter text search configuration public.wk_english\n               alter mapping for hword, hword_part, word with unaccent, english_stem';\n  end if;\n  if not exists (\n    select 1 from pg_ts_config c join pg_namespace n on n.oid = c.cfgnamespace\n    where c.cfgname = 'wk_german' and n.nspname = 'public'\n  ) then\n    execute 'create text search configuration public.wk_german (copy = german)';\n    execute 'alter text search configuration public.wk_german\n               alter mapping for hword, hword_part, word with unaccent, german_stem';\n  end if;\nend\n$do$;\n\n-- Per-source language override (null = space default). A real column, not a\n-- metadata jsonb path: retrieval-critical values do not live behind an\n-- unconstrained blob.\nalter table public.wk_sources\n  add column if not exists language text\n  check (language is null or language in ('en', 'de', 'simple'));\n\n-- Space-level configuration resolution. STABLE (reads wk_spaces), used by\n-- the insert triggers, wk_search and the backfills below. Unknown or missing\n-- language falls back to wk_english — today's behavior plus unaccent.\n-- (Replaces the 0001 immutable wk_search_config() pin, dropped below.)\ncreate or replace function public.wk_space_search_config(p_space_id uuid)\nreturns regconfig\nlanguage sql\nstable\nset search_path = public\nas $$\n  select coalesce(\n    (select case s.settings->>'language'\n              when 'de' then 'public.wk_german'::regconfig\n              when 'simple' then 'simple'::regconfig\n              else 'public.wk_english'::regconfig\n            end\n     from wk_spaces s\n     where s.id = p_space_id),\n    'public.wk_english'::regconfig\n  );\n$$;\n\n-- Source-level resolution: explicit source language wins, else the space\n-- default. Consumed by the source-chunk index (later migration); defined\n-- here so the language column and its resolution ship together.\ncreate or replace function public.wk_source_search_config(p_source_id uuid)\nreturns regconfig\nlanguage sql\nstable\nset search_path = public\nas $$\n  select coalesce(\n    (select case src.language\n              when 'de' then 'public.wk_german'::regconfig\n              when 'en' then 'public.wk_english'::regconfig\n              when 'simple' then 'simple'::regconfig\n              else public.wk_space_search_config(src.space_id)\n            end\n     from wk_sources src\n     where src.id = p_source_id),\n    'public.wk_english'::regconfig\n  );\n$$;\n\n-- Same triggers as 0001, now resolving the configuration from NEW.space_id.\n-- INSERT-only remains correct: content is immutable after insert; language\n-- changes are handled by wk_reindex_space below.\ncreate or replace function public.wk_revision_search_vector()\nreturns trigger\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  cfg regconfig := public.wk_space_search_config(new.space_id);\n  body text;\nbegin\n  body := regexp_replace(new.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '');\n  new.search_vector :=\n       setweight(to_tsvector(cfg, coalesce(new.title, '')), 'A')\n    || setweight(to_tsvector(cfg, coalesce(new.summary, '')), 'B')\n    || setweight(to_tsvector(cfg, body), 'D');\n  return new;\nend;\n$$;\n\ncreate or replace function public.wk_claim_search_vector()\nreturns trigger\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  cfg regconfig := public.wk_space_search_config(new.space_id);\nbegin\n  new.search_vector :=\n       setweight(to_tsvector(cfg, coalesce(new.subject, '')), 'A')\n    || setweight(to_tsvector(cfg, coalesce(new.object, '')), 'B')\n    || setweight(to_tsvector(cfg, coalesce(new.predicate, '')), 'C');\n  return new;\nend;\n$$;\n\n-- Recomputes one space's derived search vectors under its current language\n-- setting. Idempotent; called by the settings handler when\n-- settings.language changes (and available for manual repair). Reached only\n-- through the db.call whitelist like every other wk_ function.\ncreate or replace function public.wk_reindex_space(p_space_id uuid)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  cfg regconfig := public.wk_space_search_config(p_space_id);\n  revisions_updated bigint;\n  claims_updated bigint;\nbegin\n  update wk_concept_revisions r\n  set search_vector =\n       setweight(to_tsvector(cfg, coalesce(r.title, '')), 'A')\n    || setweight(to_tsvector(cfg, coalesce(r.summary, '')), 'B')\n    || setweight(to_tsvector(cfg, regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')), 'D')\n  where r.space_id = p_space_id;\n  get diagnostics revisions_updated = row_count;\n\n  update wk_claims cl\n  set search_vector =\n       setweight(to_tsvector(cfg, coalesce(cl.subject, '')), 'A')\n    || setweight(to_tsvector(cfg, coalesce(cl.object, '')), 'B')\n    || setweight(to_tsvector(cfg, coalesce(cl.predicate, '')), 'C')\n  where cl.space_id = p_space_id;\n  get diagnostics claims_updated = row_count;\n\n  return jsonb_build_object(\n    'space_id', p_space_id,\n    'revisions', revisions_updated,\n    'claims', claims_updated\n  );\nend;\n$$;\n\n-- Query parsing with a German stopword repair. unaccent runs BEFORE the\n-- stemmer (filtering dictionary), so the stemmer no longer recognizes the\n-- umlauted entries of its stopword list — 'für' arrives as 'fur' and\n-- survives as a content-bearing term, breaking websearch AND semantics for\n-- any document that lacks the function word. The complete set of surviving\n-- lexemes is small and fixed (the german stoplist has exactly these\n-- non-ASCII entries: daß für können könnte während würde würden über), so\n-- they are stripped from the parsed query here. German-only: 'fur' is a\n-- legitimate English word, so wk_english queries pass through untouched.\n-- Index-side occurrences of these lexemes remain as harmless noise (queries\n-- never contain them after this). client_min_messages suppresses the\n-- \"doesn't contain lexemes\" NOTICE the empty-substitute rewrites emit.\ncreate or replace function public.wk_search_tsquery(p_cfg regconfig, p_query text)\nreturns tsquery\nlanguage sql\nstable\nset search_path = public\nset client_min_messages = warning\nas $$\n  select case\n    when p_cfg = 'public.wk_german'::regconfig then\n      ts_rewrite(ts_rewrite(ts_rewrite(ts_rewrite(ts_rewrite(ts_rewrite(ts_rewrite(\n        websearch_to_tsquery(p_cfg, p_query),\n        'dass'::tsquery, ''::tsquery),\n        'fur'::tsquery, ''::tsquery),\n        'konn'::tsquery, ''::tsquery),\n        'konnt'::tsquery, ''::tsquery),\n        'wahrend'::tsquery, ''::tsquery),\n        'wurd'::tsquery, ''::tsquery),\n        'uber'::tsquery, ''::tsquery)\n    else websearch_to_tsquery(p_cfg, p_query)\n  end;\n$$;\n\n-- Trigram indexes for the slug/title fallback arm of wk_search.\ncreate index if not exists wk_concepts_slug_trgm_idx\n  on public.wk_concepts using gin (slug gin_trgm_ops);\n\ncreate index if not exists wk_concept_revisions_title_trgm_idx\n  on public.wk_concept_revisions using gin (title gin_trgm_ops);\n\n-- Same signature and return shape as 0003 (CREATE OR REPLACE cannot change\n-- RETURNS TABLE — new result columns belong to new functions). Changes:\n-- per-space configuration everywhere the 0001 pin was used, plus the trigram\n-- fallback arm on concepts.\ncreate or replace function public.wk_search(p_space_id uuid,\n  p_query text,\n  p_kind text default null,\n  p_limit int default 20\n)\nreturns table (\n  kind text,\n  concept_slug text,\n  claim_id uuid,\n  title text,\n  headline text,\n  rank real\n)\nlanguage sql\nstable\nset search_path = public\nas $$\n  with query as (\n    select public.wk_space_search_config(p_space_id) as cfg,\n           public.wk_search_tsquery(public.wk_space_search_config(p_space_id), p_query) as ts,\n           btrim(p_query) as needle\n  ),\n  concept_hits as (\n    select 'concept'::text as kind,\n           c.slug as concept_slug,\n           null::uuid as claim_id,\n           r.title as title,\n           (r.title || E'\\n' || r.summary || E'\\n' ||\n            regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')) as doc,\n           greatest(\n             (case when lower(c.slug) = lower(query.needle) then 10.0\n                   else ts_rank(r.search_vector, query.ts) end),\n             5.0 * similarity(c.slug, query.needle),\n             3.0 * word_similarity(query.needle, r.title)\n           )::real as rank,\n           query.ts as ts,\n           query.cfg as cfg\n    from wk_concepts c\n    join wk_concept_revisions r on r.id = c.current_revision_id\n    cross join query\n    where c.space_id = p_space_id\n      and (p_kind is null or p_kind = 'concept')\n      and (r.search_vector @@ query.ts\n           or lower(c.slug) = lower(query.needle)\n           or similarity(c.slug, query.needle) >= 0.45\n           or word_similarity(query.needle, r.title) >= 0.6)\n  ),\n  claim_hits as (\n    select 'claim'::text as kind,\n           c.slug as concept_slug,\n           cl.id as claim_id,\n           (cl.subject || ' ' || cl.predicate || ' ' || cl.object) as title,\n           (cl.subject || ' ' || cl.predicate || ' ' || cl.object) as doc,\n           ts_rank(cl.search_vector, query.ts)::real as rank,\n           query.ts as ts,\n           query.cfg as cfg\n    from wk_claims cl\n    join wk_concepts c on c.id = cl.concept_id\n    cross join query\n    where cl.space_id = p_space_id\n      and cl.status in ('verified', 'disputed', 'deprecated')\n      and (p_kind is null or p_kind = 'claim')\n      and cl.search_vector @@ query.ts\n  ),\n  hits as (\n    select * from concept_hits\n    union all\n    select * from claim_hits\n    order by rank desc\n    limit p_limit\n  )\n  select hits.kind,\n         hits.concept_slug,\n         hits.claim_id,\n         hits.title,\n         ts_headline(\n           hits.cfg,\n           hits.doc,\n           hits.ts,\n           'StartSel=<mark>,StopSel=</mark>,MaxWords=30'\n         ) as headline,\n         hits.rank\n  from hits\n  order by hits.rank desc;\n$$;\n\n-- Unconditional re-vectorization: every existing vector was built with the\n-- 0001 'english' pin and must be restemmed/unaccented under the per-space\n-- configuration. Runs once; on large deployments this rewrites every\n-- revision/claim row (document expected duration in release notes).\nupdate public.wk_concept_revisions r\nset search_vector =\n     setweight(to_tsvector(public.wk_space_search_config(r.space_id), coalesce(r.title, '')), 'A')\n  || setweight(to_tsvector(public.wk_space_search_config(r.space_id), coalesce(r.summary, '')), 'B')\n  || setweight(to_tsvector(public.wk_space_search_config(r.space_id), regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')), 'D');\n\nupdate public.wk_claims cl\nset search_vector =\n     setweight(to_tsvector(public.wk_space_search_config(cl.space_id), coalesce(cl.subject, '')), 'A')\n  || setweight(to_tsvector(public.wk_space_search_config(cl.space_id), coalesce(cl.object, '')), 'B')\n  || setweight(to_tsvector(public.wk_space_search_config(cl.space_id), coalesce(cl.predicate, '')), 'C');\n\n-- No legacy objects: every trigger, function and backfill above resolves the\n-- configuration per space/source — the 0001 pinned-config function has no\n-- caller left and is dropped (fresh replays: 0001/0003 used it BEFORE this\n-- statement runs; existing databases: the trigger bodies were replaced above).\ndrop function if exists public.wk_search_config();\n",
  '0017_wk_source_chunks':
    "-- Source-chunk index — the second retrieval tier (source evidence).\n--\n--   * wk_search covers APPROVED knowledge only (current revisions + visible\n--     claims). Details that never made it into a synthesized concept were\n--     unreachable: the verbatim archive existed but could not be searched.\n--     This table makes archived sources retrievable WITHOUT weakening the\n--     approval gate — chunk hits are a separate, explicitly labeled tier\n--     ('source_evidence'), composed in TypeScript strictly AFTER approved\n--     hits and only when the caller opts in (mode=approved_then_sources).\n--   * Chunks are heading-aligned projections of wk_sources.markdown\n--     (src/ingest/chunk.ts chunkForRetrieval — the single chunking\n--     implementation; the backfill worker uses the same code, which is why\n--     the backfill is app-level, not in-migration SQL).\n--   * Rows are derived data: INSERT-only alongside the immutable source,\n--     rebuilt by wk_reindex_space on language changes, healed by the scan\n--     worker for sources predating this migration. unique(source_id,\n--     chunk_index) makes persistence idempotent.\n--   * Ranking stays in SQL behind the db.call whitelist (wk_search_sources),\n--     mirroring wk_search. The two functions are never merged: ts_rank\n--     values across different corpora are not comparable, and the tier\n--     separation IS the explainability story.\ncreate table if not exists public.wk_source_chunks (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  source_id uuid not null references public.wk_sources(id) on delete cascade,\n  chunk_index int not null check (chunk_index >= 0),\n  heading text,\n  content text not null,\n  tokens int not null check (tokens > 0),\n  search_vector tsvector,\n  created_at timestamptz not null default now(),\n  unique (source_id, chunk_index)\n);\n\ncreate index if not exists wk_source_chunks_search_idx\n  on public.wk_source_chunks using gin (search_vector);\n\ncreate index if not exists wk_source_chunks_source_idx\n  on public.wk_source_chunks (source_id);\n\ncreate index if not exists wk_source_chunks_space_idx\n  on public.wk_source_chunks (space_id);\n\n-- INSERT-only trigger, like revisions/claims: chunk content is immutable\n-- (it mirrors the immutable source); language changes go through\n-- wk_reindex_space. Weights: heading=A, body=C — a heading match should\n-- outrank a body match, but chunks never outrank title-weighted concept\n-- vectors in their own tier anyway (tiers are ranked independently).\ncreate or replace function public.wk_source_chunk_search_vector()\nreturns trigger\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  cfg regconfig := public.wk_source_search_config(new.source_id);\nbegin\n  new.search_vector :=\n       setweight(to_tsvector(cfg, coalesce(new.heading, '')), 'A')\n    || setweight(to_tsvector(cfg, new.content), 'C');\n  return new;\nend;\n$$;\n\ndrop trigger if exists wk_source_chunk_search_vector_insert on public.wk_source_chunks;\ncreate trigger wk_source_chunk_search_vector_insert\n  before insert on public.wk_source_chunks\n  for each row execute function public.wk_source_chunk_search_vector();\n\n-- wk_reindex_space grows the chunk arm (same signature; 0016 defined the\n-- revisions/claims arms).\ncreate or replace function public.wk_reindex_space(p_space_id uuid)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  cfg regconfig := public.wk_space_search_config(p_space_id);\n  revisions_updated bigint;\n  claims_updated bigint;\n  chunks_updated bigint;\nbegin\n  update wk_concept_revisions r\n  set search_vector =\n       setweight(to_tsvector(cfg, coalesce(r.title, '')), 'A')\n    || setweight(to_tsvector(cfg, coalesce(r.summary, '')), 'B')\n    || setweight(to_tsvector(cfg, regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')), 'D')\n  where r.space_id = p_space_id;\n  get diagnostics revisions_updated = row_count;\n\n  update wk_claims cl\n  set search_vector =\n       setweight(to_tsvector(cfg, coalesce(cl.subject, '')), 'A')\n    || setweight(to_tsvector(cfg, coalesce(cl.object, '')), 'B')\n    || setweight(to_tsvector(cfg, coalesce(cl.predicate, '')), 'C')\n  where cl.space_id = p_space_id;\n  get diagnostics claims_updated = row_count;\n\n  -- Chunk vectors resolve per SOURCE (source language overrides the space\n  -- default), so the chunk arm recomputes through wk_source_search_config.\n  update wk_source_chunks ch\n  set search_vector =\n       setweight(to_tsvector(public.wk_source_search_config(ch.source_id), coalesce(ch.heading, '')), 'A')\n    || setweight(to_tsvector(public.wk_source_search_config(ch.source_id), ch.content), 'C')\n  where ch.space_id = p_space_id;\n  get diagnostics chunks_updated = row_count;\n\n  return jsonb_build_object(\n    'space_id', p_space_id,\n    'revisions', revisions_updated,\n    'claims', claims_updated,\n    'chunks', chunks_updated\n  );\nend;\n$$;\n\n-- Ranked FTS over archived source chunks — the 'source_evidence' tier.\n-- Everything archived is searchable here BY DESIGN: this tier exists to\n-- surface not-yet-curated material, clearly labeled as such by the caller.\n-- The space config parses the query; per-source configs built the vectors\n-- (a per-source query parse is impossible in one statement — the accepted\n-- asymmetry for mixed-language spaces, bounded by unaccent + the shared\n-- stopword repair and measured by the retrieval eval).\ncreate or replace function public.wk_search_sources(\n  p_space_id uuid,\n  p_query text,\n  p_limit int default 20\n)\nreturns table (\n  source_id uuid,\n  chunk_id uuid,\n  chunk_index int,\n  title text,\n  url text,\n  heading text,\n  headline text,\n  rank real\n)\nlanguage sql\nstable\nset search_path = public\nas $$\n  with query as (\n    select public.wk_space_search_config(p_space_id) as cfg,\n           public.wk_search_tsquery(public.wk_space_search_config(p_space_id), p_query) as ts\n  ),\n  hits as (\n    select ch.source_id,\n           ch.id as chunk_id,\n           ch.chunk_index,\n           s.title,\n           s.url,\n           ch.heading,\n           ch.content as doc,\n           ts_rank(ch.search_vector, query.ts)::real as rank,\n           query.ts as ts,\n           query.cfg as cfg\n    from wk_source_chunks ch\n    join wk_sources s on s.id = ch.source_id\n    cross join query\n    where ch.space_id = p_space_id\n      and ch.search_vector @@ query.ts\n    order by rank desc\n    limit p_limit\n  )\n  select hits.source_id,\n         hits.chunk_id,\n         hits.chunk_index,\n         hits.title,\n         hits.url,\n         hits.heading,\n         ts_headline(\n           hits.cfg,\n           hits.doc,\n           hits.ts,\n           'StartSel=<mark>,StopSel=</mark>,MaxWords=30'\n         ) as headline,\n         hits.rank\n  from hits\n  order by hits.rank desc;\n$$;\n",
  '0018_wk_embeddings':
    "-- Optional embeddings — a SECOND ranker for retrieval, never a replacement.\n--\n--   * Lexical FTS (0016/0017) stays the deterministic floor: everything\n--     vector-related in this migration is wrapped in a pgvector guard and\n--     no-ops cleanly on a server without the extension. TypeScript only ever\n--     calls the hybrid functions after a startup capability probe AND with a\n--     configured embedding provider — retrieval never fails because of\n--     embeddings, it silently stays lexical.\n--   * wk_embeddings is a SIDE table (one row per object × model), not\n--     columns on the hot tables: one guarded object instead of three guarded\n--     ALTERs, uniform for revisions/claims/source chunks, and hot-table\n--     shapes stay identical across deployments with and without pgvector.\n--   * Fusion is Reciprocal Rank Fusion (k=60) over RANK POSITIONS, computed\n--     in SQL: rrf = 1/(60+lex_pos) + 1/(60+vec_pos), with coalesce so a\n--     hit found by only one arm still ranks (partially-embedded corpora stay\n--     correct during backfill). Deterministic and explainable — matched_via\n--     reports which arm(s) found each hit.\n--   * Visibility is restated in BOTH arms (current revisions, visible claim\n--     statuses): proposed content stays invisible by construction in the\n--     vector arm too, not by filter discipline.\n--   * Dimensions are pinned to 1536 (text-embedding-3-small native;\n--     gemini requested at 1536) — the provider layer refuses mismatched\n--     models loudly.\n\n-- Unconditional: the audit ledger learns the 'embed' kind (adjudicate has\n-- been allowed since 0002). Must land before the embedder worker ships.\nalter table public.wk_agent_runs\n  drop constraint if exists wk_agent_runs_kind_check;\n\nalter table public.wk_agent_runs\n  add constraint wk_agent_runs_kind_check\n  check (kind in ('classify', 'synthesize', 'answer', 'distill', 'adjudicate', 'embed'));\n\n-- Everything below requires pgvector. A deployment without it gets a clean\n-- no-op — and must re-run migrations (or install the extension and call this\n-- block manually) after adding pgvector; restoring a post-0018 dump onto a\n-- server without pgvector is out of scope (documented).\ndo $guard$\nbegin\n  if not exists (select 1 from pg_available_extensions where name = 'vector') then\n    raise notice 'pgvector not available — skipping wk_embeddings (retrieval stays lexical)';\n    return;\n  end if;\n\n  execute 'create extension if not exists vector';\n\n  execute $ddl$\n    create table if not exists public.wk_embeddings (\n      id uuid primary key default gen_random_uuid(),\n      space_id uuid not null references public.wk_spaces(id) on delete cascade,\n      object_kind text not null check (object_kind in ('revision', 'claim', 'source_chunk')),\n      object_id uuid not null,\n      model text not null,\n      embedding vector(1536) not null,\n      created_at timestamptz not null default now(),\n      unique (object_kind, object_id, model)\n    )\n  $ddl$;\n\n  execute 'create index if not exists wk_embeddings_hnsw_idx on public.wk_embeddings using hnsw (embedding vector_cosine_ops)';\n  execute 'create index if not exists wk_embeddings_space_idx on public.wk_embeddings (space_id)';\n\n  -- Hybrid search over approved knowledge: wk_search's lexical arms + a\n  -- cosine-distance arm over wk_embeddings, fused by RRF. Same visibility\n  -- joins as wk_search, same headline pass; new columns rank (= rrf score)\n  -- and matched_via. Both arms read 4x the page size so fusion has depth.\n  execute $fn$\n    create or replace function public.wk_search_hybrid(\n      p_space_id uuid,\n      p_query text,\n      p_embedding text,\n      p_kind text default null,\n      p_limit int default 20\n    )\n    returns table (\n      kind text,\n      concept_slug text,\n      claim_id uuid,\n      title text,\n      headline text,\n      rank real,\n      matched_via text\n    )\n    language sql\n    stable\n    set search_path = public\n    as $body$\n      with query as (\n        select public.wk_space_search_config(p_space_id) as cfg,\n               public.wk_search_tsquery(public.wk_space_search_config(p_space_id), p_query) as ts,\n               btrim(p_query) as needle,\n               p_embedding::vector(1536) as emb\n      ),\n      lex_raw as (\n        select 'concept'::text as kind,\n               c.slug as concept_slug,\n               null::uuid as claim_id,\n               r.title as title,\n               (r.title || E'\\n' || r.summary || E'\\n' ||\n                regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')) as doc,\n               greatest(\n                 (case when lower(c.slug) = lower(query.needle) then 10.0\n                       else ts_rank(r.search_vector, query.ts) end),\n                 5.0 * similarity(c.slug, query.needle),\n                 3.0 * word_similarity(query.needle, r.title)\n               )::real as lex_rank\n        from wk_concepts c\n        join wk_concept_revisions r on r.id = c.current_revision_id\n        cross join query\n        where c.space_id = p_space_id\n          and (p_kind is null or p_kind = 'concept')\n          and (r.search_vector @@ query.ts\n               or lower(c.slug) = lower(query.needle)\n               or similarity(c.slug, query.needle) >= 0.45\n               or word_similarity(query.needle, r.title) >= 0.6)\n        union all\n        select 'claim'::text,\n               c.slug,\n               cl.id,\n               (cl.subject || ' ' || cl.predicate || ' ' || cl.object),\n               (cl.subject || ' ' || cl.predicate || ' ' || cl.object),\n               ts_rank(cl.search_vector, query.ts)::real\n        from wk_claims cl\n        join wk_concepts c on c.id = cl.concept_id\n        cross join query\n        where cl.space_id = p_space_id\n          and cl.status in ('verified', 'disputed', 'deprecated')\n          and (p_kind is null or p_kind = 'claim')\n          and cl.search_vector @@ query.ts\n      ),\n      lex as (\n        select *, row_number() over (order by lex_rank desc) as pos\n        from lex_raw\n        order by lex_rank desc\n        limit (p_limit * 4)\n      ),\n      vec_raw as (\n        select 'concept'::text as kind,\n               c.slug as concept_slug,\n               null::uuid as claim_id,\n               r.title as title,\n               (r.title || E'\\n' || r.summary || E'\\n' ||\n                regexp_replace(r.markdown, '^---\\r?\\n.*?\\r?\\n---(?:\\r?\\n)?', '')) as doc,\n               (e.embedding <=> query.emb) as dist\n        from wk_embeddings e\n        join wk_concept_revisions r on e.object_kind = 'revision' and r.id = e.object_id\n        join wk_concepts c on c.current_revision_id = r.id\n        cross join query\n        where e.space_id = p_space_id\n          and (p_kind is null or p_kind = 'concept')\n        union all\n        select 'claim'::text,\n               c.slug,\n               cl.id,\n               (cl.subject || ' ' || cl.predicate || ' ' || cl.object),\n               (cl.subject || ' ' || cl.predicate || ' ' || cl.object),\n               (e.embedding <=> query.emb)\n        from wk_embeddings e\n        join wk_claims cl on e.object_kind = 'claim' and cl.id = e.object_id\n        join wk_concepts c on c.id = cl.concept_id\n        cross join query\n        where e.space_id = p_space_id\n          and cl.status in ('verified', 'disputed', 'deprecated')\n          and (p_kind is null or p_kind = 'claim')\n      ),\n      vec as (\n        select *, row_number() over (order by dist asc) as pos\n        from vec_raw\n        order by dist asc\n        limit (p_limit * 4)\n      ),\n      fused as (\n        select coalesce(l.kind, v.kind) as kind,\n               coalesce(l.concept_slug, v.concept_slug) as concept_slug,\n               coalesce(l.claim_id, v.claim_id) as claim_id,\n               coalesce(l.title, v.title) as title,\n               coalesce(l.doc, v.doc) as doc,\n               (coalesce(1.0 / (60 + l.pos), 0) + coalesce(1.0 / (60 + v.pos), 0))::real as rrf,\n               case\n                 when l.pos is not null and v.pos is not null then 'both'\n                 when l.pos is not null then 'lexical'\n                 else 'vector'\n               end as matched_via\n        from lex l\n        full outer join vec v\n          on l.kind = v.kind\n         and l.concept_slug is not distinct from v.concept_slug\n         and l.claim_id is not distinct from v.claim_id\n      ),\n      page as (\n        select * from fused order by rrf desc limit p_limit\n      )\n      select page.kind,\n             page.concept_slug,\n             page.claim_id,\n             page.title,\n             ts_headline(\n               (select cfg from query),\n               page.doc,\n               (select ts from query),\n               'StartSel=<mark>,StopSel=</mark>,MaxWords=30'\n             ) as headline,\n             page.rrf as rank,\n             page.matched_via\n      from page\n      order by page.rrf desc;\n    $body$\n  $fn$;\n\n  -- Hybrid over the source-evidence tier (wk_source_chunks), same fusion.\n  execute $fn$\n    create or replace function public.wk_search_sources_hybrid(\n      p_space_id uuid,\n      p_query text,\n      p_embedding text,\n      p_limit int default 20\n    )\n    returns table (\n      source_id uuid,\n      chunk_id uuid,\n      chunk_index int,\n      title text,\n      url text,\n      heading text,\n      headline text,\n      rank real,\n      matched_via text\n    )\n    language sql\n    stable\n    set search_path = public\n    as $body$\n      with query as (\n        select public.wk_space_search_config(p_space_id) as cfg,\n               public.wk_search_tsquery(public.wk_space_search_config(p_space_id), p_query) as ts,\n               p_embedding::vector(1536) as emb\n      ),\n      lex as (\n        select ch.id as chunk_id, ts_rank(ch.search_vector, query.ts) as lex_rank,\n               row_number() over (order by ts_rank(ch.search_vector, query.ts) desc) as pos\n        from wk_source_chunks ch\n        cross join query\n        where ch.space_id = p_space_id\n          and ch.search_vector @@ query.ts\n        order by lex_rank desc\n        limit (p_limit * 4)\n      ),\n      vec as (\n        select e.object_id as chunk_id,\n               row_number() over (order by e.embedding <=> query.emb) as pos\n        from wk_embeddings e\n        cross join query\n        where e.space_id = p_space_id\n          and e.object_kind = 'source_chunk'\n        order by (e.embedding <=> query.emb) asc\n        limit (p_limit * 4)\n      ),\n      fused as (\n        select coalesce(l.chunk_id, v.chunk_id) as chunk_id,\n               (coalesce(1.0 / (60 + l.pos), 0) + coalesce(1.0 / (60 + v.pos), 0))::real as rrf,\n               case\n                 when l.pos is not null and v.pos is not null then 'both'\n                 when l.pos is not null then 'lexical'\n                 else 'vector'\n               end as matched_via\n        from lex l\n        full outer join vec v on l.chunk_id = v.chunk_id\n      ),\n      page as (\n        select * from fused order by rrf desc limit p_limit\n      )\n      select ch.source_id,\n             ch.id as chunk_id,\n             ch.chunk_index,\n             s.title,\n             s.url,\n             ch.heading,\n             ts_headline(\n               (select cfg from query),\n               ch.content,\n               (select ts from query),\n               'StartSel=<mark>,StopSel=</mark>,MaxWords=30'\n             ) as headline,\n             page.rrf as rank,\n             page.matched_via\n      from page\n      join wk_source_chunks ch on ch.id = page.chunk_id\n      join wk_sources s on s.id = ch.source_id\n      order by page.rrf desc;\n    $body$\n  $fn$;\nend\n$guard$;\n",
  '0019_wk_source_sync':
    "-- Versioned source-sync contract — the connector-facing ingest surface.\n--\n--   * WikiKit builds no connectors; an external workflow platform pushes\n--     documents. What was missing is a stable identity ACROSS pushes: until\n--     now a source was identified only by content hash, so two versions of\n--     the same external document were two unrelated rows and upstream\n--     deletion was inexpressible.\n--   * wk_source_streams holds the MUTABLE per-external-id state: the head\n--     pointer, latest version marker and the tombstone. wk_sources stays\n--     100% immutable — every new column below is written once at INSERT and\n--     never touched; content-hash dedup and the append-only verbatim archive\n--     are unchanged.\n--   * A content REVERT (v3 byte-identical to v1) is the case that forces\n--     this shape: unique(space_id, content_hash) correctly refuses a second\n--     row, so per-row version columns record the version under which the\n--     content was FIRST observed, while the stream's head pointer and\n--     latest_version carry current truth.\n--   * Tombstone is a soft flag on the stream (deleted_at), never a delete:\n--     cited sources are undeletable by design (wk_citations RESTRICT), and\n--     the archived bytes remain evidence of what the document said. A\n--     re-push after a tombstone resurrects the stream (the connector says\n--     the document exists again).\n--   * No backfill and no retro-streams from URLs: a URL was never identity,\n--     and inventing streams for historical rows would be non-deterministic.\ncreate table if not exists public.wk_source_streams (\n  id uuid primary key default gen_random_uuid(),\n  space_id uuid not null references public.wk_spaces(id) on delete cascade,\n  external_source_id text not null check (length(external_source_id) between 1 and 500),\n  latest_source_id uuid references public.wk_sources(id),\n  latest_version text,\n  latest_observed_at timestamptz,\n  metadata jsonb not null default '{}'::jsonb,\n  deleted_at timestamptz,\n  created_at timestamptz not null default now(),\n  updated_at timestamptz not null default now(),\n  unique (space_id, external_source_id)\n);\n\ndrop trigger if exists wk_source_streams_touch_updated_at on public.wk_source_streams;\ncreate trigger wk_source_streams_touch_updated_at\n  before update on public.wk_source_streams\n  for each row execute function public.wk_touch_updated_at();\n\n-- Write-once version columns on the immutable archive rows.\nalter table public.wk_sources\n  add column if not exists stream_id uuid references public.wk_source_streams(id) on delete set null,\n  add column if not exists source_version text,\n  add column if not exists observed_at timestamptz,\n  add column if not exists effective_at timestamptz,\n  add column if not exists supersedes_source_id uuid references public.wk_sources(id);\n\ncreate index if not exists wk_sources_stream_idx\n  on public.wk_sources (stream_id, created_at desc)\n  where stream_id is not null;\n",
  '0020_wk_review_operations':
    "-- Review operations — split/defer and request-changes.\n--\n--   * Atomic proposals are right for review integrity but wrong for review\n--     ERGONOMICS: one large source can touch many concepts, and a reviewer\n--     must be able to approve the good parts without losing the rest.\n--   * wk_split_proposal moves staged rows (revisions, claims — citations ride\n--     on claim_id —, proposed relations, removal MARKERS, decisions) to child\n--     proposals by re-pointing proposal_id. It is exactly the class of\n--     mutation the \"proposal state changes happen ONLY in SQL functions\"\n--     invariant exists for: multi-table, atomic with the parent status flip\n--     and the outbox event.\n--   * Defer IS split with a subset: named concepts are extracted into ONE\n--     pending child; the parent keeps its id (review URL stays alive) and its\n--     remainder, and its input_hash is re-salted so a fresh full re-ingest of\n--     the same sources creates a NEW complete proposal instead of converging\n--     on the now-partial one. A full split flips the parent to the new\n--     terminal status 'split'.\n--   * Child input_hash = sha256(parent hash + ':' + slug): deterministic\n--     (retries collide onto proposal_not_pending, never duplicate children)\n--     and never trips the pending-dedup index.\n--   * Request-changes is a TERMINAL reject plus a machine-readable flag —\n--     never a fifth non-terminal state: a non-terminal state would need\n--     pending-dedup, apply-guard and MCP handling everywhere, and WikiKit has\n--     no rebase anyway — acting on feedback IS a fresh proposal. Agents see\n--     changes_requested + review_note and know to revise-and-re-propose.\n--     The note is mandatory: a bounce without guidance is just a reject.\nalter table public.wk_change_proposals\n  drop constraint if exists wk_change_proposals_status_check;\nalter table public.wk_change_proposals\n  add constraint wk_change_proposals_status_check\n  check (status in ('pending', 'approved', 'rejected', 'failed', 'split'));\n\nalter table public.wk_change_proposals\n  add column if not exists parent_proposal_id uuid references public.wk_change_proposals(id) on delete set null,\n  add column if not exists changes_requested boolean not null default false;\n\ncreate index if not exists wk_change_proposals_parent_idx\n  on public.wk_change_proposals (parent_proposal_id)\n  where parent_proposal_id is not null;\n\ncreate or replace function public.wk_split_proposal(\n  p_proposal_id uuid,\n  p_reviewer text,\n  p_concepts text[] default null,\n  p_review_channel text default 'rest'\n)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  proposal record;\n  space_slug text;\n  staged_slugs text[];\n  target_slugs text[];\n  decision_count int;\n  leftover_markers int;\n  v_slug text;\n  target_concept_id uuid;\n  child_id uuid;\n  children jsonb := '[]'::jsonb;\n  full_split boolean;\nbegin\n  if p_review_channel is null or p_review_channel not in ('rest', 'mcp_elicitation') then\n    raise exception 'invalid_review_channel';\n  end if;\n\n  select * into proposal from wk_change_proposals where id = p_proposal_id for update;\n  if not found then raise exception 'proposal_not_found'; end if;\n  if proposal.status <> 'pending' then raise exception 'proposal_not_pending'; end if;\n\n  select s.slug into space_slug from wk_spaces s where s.id = proposal.space_id;\n\n  select coalesce(array_agg(distinct c.slug), '{}') into staged_slugs\n    from wk_concept_revisions r\n    join wk_concepts c on c.id = r.concept_id\n   where r.proposal_id = p_proposal_id and r.status = 'proposed';\n\n  select count(*) into decision_count\n    from wk_decisions where proposal_id = p_proposal_id and status = 'proposed';\n\n  full_split := p_concepts is null;\n\n  if full_split then\n    target_slugs := staged_slugs;\n    -- Splitting must produce MORE reviewable units than the parent was:\n    -- a single-concept proposal without decisions (or an empty/removal-only\n    -- one) has nothing to split apart.\n    if coalesce(array_length(staged_slugs, 1), 0) = 0\n       or (array_length(staged_slugs, 1) = 1 and decision_count = 0) then\n      raise exception 'split_nothing_left';\n    end if;\n  else\n    select coalesce(array_agg(distinct s), '{}') into target_slugs from unnest(p_concepts) s;\n    if coalesce(array_length(target_slugs, 1), 0) = 0 then raise exception 'unknown_split_slug'; end if;\n    if exists (select 1 from unnest(target_slugs) s where s <> all (staged_slugs)) then\n      raise exception 'unknown_split_slug';\n    end if;\n    -- A subset covering EVERY staged concept is a full split the caller\n    -- should have asked for (the parent would keep nothing but decisions).\n    if not exists (select 1 from unnest(staged_slugs) s where s <> all (target_slugs)) then\n      raise exception 'split_nothing_left';\n    end if;\n  end if;\n\n  foreach v_slug in array target_slugs loop\n    select c.id into target_concept_id\n      from wk_concepts c where c.space_id = proposal.space_id and c.slug = v_slug;\n\n    insert into wk_change_proposals\n      (space_id, status, title, summary, input_hash, source_ids, agent_meta, parent_proposal_id)\n    values\n      (proposal.space_id,\n       'pending',\n       proposal.title || ' — ' || v_slug,\n       proposal.summary,\n       encode(digest(proposal.input_hash || ':' || v_slug, 'sha256'), 'hex'),\n       proposal.source_ids,\n       coalesce(proposal.agent_meta, '{}'::jsonb) || jsonb_build_object('split_from', p_proposal_id),\n       p_proposal_id)\n    returning id into child_id;\n\n    update wk_concept_revisions set proposal_id = child_id\n     where proposal_id = p_proposal_id and concept_id = target_concept_id and status = 'proposed';\n    update wk_claims set proposal_id = child_id\n     where proposal_id = p_proposal_id and concept_id = target_concept_id and status = 'proposed';\n    update wk_relations set proposal_id = child_id\n     where proposal_id = p_proposal_id and from_concept_id = target_concept_id and status = 'proposed';\n    -- Removal markers ride on removal_proposal_id (0014), grouped under the\n    -- concept the edge leaves from.\n    update wk_relations set removal_proposal_id = child_id\n     where removal_proposal_id = p_proposal_id and from_concept_id = target_concept_id;\n\n    children := children || jsonb_build_object('proposal_id', child_id, 'concepts', jsonb_build_array(v_slug));\n  end loop;\n\n  if full_split then\n    select count(*) into leftover_markers\n      from wk_relations where removal_proposal_id = p_proposal_id;\n    if decision_count > 0 or leftover_markers > 0 then\n      -- Decisions (and markers whose from-concept was not staged) get their\n      -- own child so nothing staged is orphaned on a terminal parent.\n      insert into wk_change_proposals\n        (space_id, status, title, summary, input_hash, source_ids, agent_meta, parent_proposal_id)\n      values\n        (proposal.space_id,\n         'pending',\n         proposal.title || ' — decisions',\n         proposal.summary,\n         encode(digest(proposal.input_hash || ':decisions', 'sha256'), 'hex'),\n         proposal.source_ids,\n         coalesce(proposal.agent_meta, '{}'::jsonb) || jsonb_build_object('split_from', p_proposal_id),\n         p_proposal_id)\n      returning id into child_id;\n      update wk_decisions set proposal_id = child_id\n       where proposal_id = p_proposal_id and status = 'proposed';\n      update wk_relations set removal_proposal_id = child_id\n       where removal_proposal_id = p_proposal_id;\n      children := children || jsonb_build_object('proposal_id', child_id, 'concepts', '[]'::jsonb);\n    end if;\n\n    update wk_change_proposals\n       set status = 'split', reviewer = p_reviewer, reviewed_at = now(), review_channel = p_review_channel\n     where id = p_proposal_id;\n  else\n    -- Defer: the parent stays pending with the remainder. Re-salt its\n    -- input_hash so a full re-ingest of the same sources stages a fresh\n    -- COMPLETE proposal instead of converging on this partial one.\n    update wk_change_proposals\n       set input_hash = encode(digest(proposal.input_hash || ':remainder:' || array_to_string(target_slugs, ','), 'sha256'), 'hex')\n     where id = p_proposal_id;\n  end if;\n\n  insert into wk_outbox_events (space_id, event_type, payload)\n  values (proposal.space_id, 'wikikit.proposal.split', jsonb_build_object(\n    'space', space_slug,\n    'parent_id', p_proposal_id,\n    'parent_status', case when full_split then 'split' else 'pending' end,\n    'children', children,\n    'reviewer', p_reviewer\n  ));\n\n  return jsonb_build_object(\n    'parent', jsonb_build_object('id', p_proposal_id, 'status', case when full_split then 'split' else 'pending' end),\n    'children', children\n  );\nend;\n$$;\n\n-- Request-changes: terminal reject + flag, note mandatory. A separate\n-- function (not a fifth wk_reject_proposal argument): default-argument\n-- overloads would be ambiguous, and the db.call whitelist pins exact arity.\ncreate or replace function public.wk_request_changes(\n  p_proposal_id uuid,\n  p_reviewer text,\n  p_note text,\n  p_review_channel text default 'rest'\n)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  result jsonb;\nbegin\n  if p_note is null or btrim(p_note) = '' then\n    raise exception 'note_required';\n  end if;\n\n  select public.wk_reject_proposal(p_proposal_id, p_reviewer, p_note, p_review_channel) into result;\n\n  update wk_change_proposals set changes_requested = true where id = p_proposal_id;\n\n  update wk_outbox_events\n     set event_type = 'wikikit.proposal.changes_requested',\n         payload = payload || jsonb_build_object('changes_requested', true)\n   where event_type = 'wikikit.proposal.rejected'\n     and payload->>'proposal_id' = p_proposal_id::text;\n\n  return result || jsonb_build_object('changes_requested', true);\nend;\n$$;\n",
  '0021_wk_claim_semantics':
    "-- Richer claim semantics — the ADDITIVE half (the apply-function rewrite is\n-- 0022, kept separate so the risky function swap reviews/reverts on its own).\n--\n--   * The exact-frame rule (same subject+predicate, different object) is\n--     robust but too coarse: firmware versions, architecture states and\n--     product facts are often TEMPORALLY different, not contradictory, and\n--     often scoped to a context (region, product version, tenant).\n--   * context: a nullable text partition of the frame — the frame key\n--     becomes (subject, predicate, coalesce(context,'')). Text, not jsonb:\n--     equality must be deterministic and diffs human-readable ('region:eu').\n--     NULL = universal.\n--   * object_normalized / object_value_num / object_unit: the canonical\n--     comparison form, computed SERVER-SIDE at staging from the space's\n--     predicate registry (settings.predicate_defs — typed predicates with\n--     explicit unit-conversion factors; no built-in unit ontology). All\n--     nullable: comparison sites use coalesce(object_normalized, object), so\n--     pre-0021 rows behave exactly as before with NO backfill.\n--   * supersedes_claim_id: staged, reviewer-visible succession — approval\n--     deprecates the referenced claim deterministically (0022 flip 5c),\n--     never as an implicit LLM side effect.\nalter table public.wk_claims\n  add column if not exists context text\n    check (context is null or length(context) between 1 and 200),\n  add column if not exists object_normalized text,\n  add column if not exists object_value_num numeric,\n  add column if not exists object_unit text,\n  add column if not exists supersedes_claim_id uuid references public.wk_claims(id);\n\ncreate index if not exists wk_claims_frame_ctx_idx\n  on public.wk_claims (space_id, subject, predicate, coalesce(context, ''));\n\n-- wk_functional_predicates v2: settings.predicate_defs (the typed registry,\n-- [{name, type, functional, unit?, enum_values?}]) is consulted FIRST; the\n-- legacy settings.functional_predicates array remains as fallback and both\n-- are unioned — declaring a registry must never silently drop an existing\n-- functional declaration. Same signature (create or replace).\ncreate or replace function public.wk_functional_predicates(p_space_id uuid)\nreturns text[]\nlanguage sql\nstable\nset search_path = public\nas $$\n  select coalesce(array_agg(distinct name), '{}'::text[])\n  from (\n    select def->>'name' as name\n    from wk_spaces s\n    cross join lateral jsonb_array_elements(\n      case\n        when jsonb_typeof(s.settings->'predicate_defs') = 'array'\n          then s.settings->'predicate_defs'\n        else '[]'::jsonb\n      end\n    ) as def\n    where s.id = p_space_id\n      and (def->>'functional')::boolean is true\n      and def->>'name' is not null\n    union all\n    select item.value\n    from wk_spaces s\n    cross join lateral jsonb_array_elements_text(\n      case\n        when jsonb_typeof(s.settings->'functional_predicates') = 'array'\n          then s.settings->'functional_predicates'\n        else '[]'::jsonb\n      end\n    ) as item(value)\n    where s.id = p_space_id\n  ) names\n  where name is not null;\n$$;\n",
  '0022_wk_apply_claim_semantics':
    "-- Apply-core rewrite for the 0021 claim semantics — interval-, context- and\n-- normalization-aware disputes plus deterministic supersession.\n-- Same-signature CREATE OR REPLACE of wk_apply_proposal_core_0003 (the 0014\n-- precedent; the name is the historical rename anchor from the RELEASED 0010\n-- migration and cannot change): the 0010 four-argument public wrapper keeps\n-- calling the core unchanged, and the raise messages stay exactly\n-- 'proposal_not_found' / 'proposal_not_pending' / 'stale_base'.\n--\n-- Changes over 0014, all confined to the claim flips:\n--   * Flip 5 pairs additionally require: same context partition\n--     (coalesce(context,'')), NORMALIZED object inequality\n--     (coalesce(object_normalized, object)), OVERLAPPING validity intervals\n--     (disjoint validity = succession, not contradiction), no\n--     adjudication='complementary' stamp on the incoming claim (the\n--     adjudicator's verdict is staged in agent_meta and visible in the\n--     review diff — the human approved it), and the pair is not an explicit\n--     supersession (those take flip 5c).\n--   * Flip 5c (new, runs BEFORE flip 5): fresh verified claims carrying\n--     supersedes_claim_id deprecate their target deterministically and\n--     upsert a 'supersedes' relation between differing concepts. Running\n--     first removes the deprecated side from the visible statuses flip 5\n--     joins on — a superseded claim never also becomes disputed.\n--   * The result carries claims_deprecated (wire: ApplyResult).\ncreate or replace function public.wk_apply_proposal_core_0003(p_proposal_id uuid, p_reviewer text, p_note text default null)\nreturns jsonb\nlanguage plpgsql\nset search_path = public\nas $$\ndeclare\n  proposal public.wk_change_proposals%rowtype;\n  space_slug text;\n  concept_slugs text[] := '{}';\n  claims_verified integer := 0;\n  claims_disputed integer := 0;\n  claims_deprecated integer := 0;\n  relations_removed_count integer := 0;\nbegin\n  select * into proposal from wk_change_proposals where id = p_proposal_id for update;\n  if not found then\n    raise exception 'proposal_not_found';\n  end if;\n  if proposal.status <> 'pending' then\n    raise exception 'proposal_not_pending';\n  end if;\n\n  select slug into space_slug from wk_spaces where id = proposal.space_id;\n\n  -- Lock every affected concept row, in id order so two proposals sharing a\n  -- concept subset can never deadlock. Includes the endpoints of relations\n  -- this proposal marks for removal — they may have no staged revision.\n  perform 1\n  from wk_concepts c\n  where c.id in (\n    select r.concept_id from wk_concept_revisions r where r.proposal_id = p_proposal_id\n    union\n    select rel.from_concept_id from wk_relations rel where rel.removal_proposal_id = p_proposal_id\n    union\n    select rel.to_concept_id from wk_relations rel where rel.removal_proposal_id = p_proposal_id\n  )\n  order by c.id\n  for update;\n\n  -- Stale-base check (unchanged).\n  if exists (\n    select 1\n    from wk_concept_revisions r\n    join wk_concepts c on c.id = r.concept_id\n    where r.proposal_id = p_proposal_id\n      and r.status = 'proposed'\n      and c.current_revision_id is distinct from r.base_revision_id\n  ) then\n    raise exception 'stale_base';\n  end if;\n\n  -- Flip 1: previous current revisions of the touched concepts → superseded.\n  update wk_concept_revisions old\n  set status = 'superseded'\n  from wk_concept_revisions fresh\n  join wk_concepts c on c.id = fresh.concept_id\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'proposed'\n    and old.id = c.current_revision_id;\n\n  -- Flip 2: proposed revisions → current.\n  update wk_concept_revisions\n  set status = 'current'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 3: repoint the concept (and mirror the revision title so list\n  -- endpoints never show a stale title).\n  update wk_concepts c\n  set current_revision_id = fresh.id,\n      title = fresh.title,\n      updated_at = now()\n  from wk_concept_revisions fresh\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'current'\n    and c.id = fresh.concept_id;\n\n  -- Flip 4: proposed claims → verified.\n  update wk_claims\n  set status = 'verified'\n  where proposal_id = p_proposal_id and status = 'proposed';\n  get diagnostics claims_verified = row_count;\n\n  -- Flip 5c: explicit supersession — deterministic, staged, reviewer-visible.\n  update wk_claims old\n  set status = 'deprecated'\n  from wk_claims fresh\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'verified'\n    and fresh.supersedes_claim_id = old.id\n    and old.status in ('verified', 'disputed');\n  get diagnostics claims_deprecated = row_count;\n\n  -- Supersedes relation between the carrying concepts (mirror of flip 5b).\n  insert into wk_relations (space_id, from_concept_id, to_concept_id, kind, status, proposal_id)\n  select distinct fresh.space_id, fresh.concept_id, old.concept_id, 'supersedes', 'active', p_proposal_id\n  from wk_claims fresh\n  join wk_claims old on old.id = fresh.supersedes_claim_id\n  where fresh.proposal_id = p_proposal_id\n    and fresh.status = 'verified'\n    and old.status = 'deprecated'\n    and fresh.concept_id <> old.concept_id\n  on conflict (space_id, from_concept_id, to_concept_id, kind)\n    do update set status = 'active', removal_proposal_id = null;\n\n  -- Flip 5: interval-, context- and normalization-aware disputes on\n  -- functional predicates. The status filters are stable under the flip\n  -- itself ({verified,disputed} on either side), so the pair set is\n  -- identical when recomputed for the relation insert below.\n  with pairs as (\n    select fresh.id as fresh_id, old.id as old_id\n    from wk_claims fresh\n    join wk_claims old\n      on old.space_id = fresh.space_id\n     and old.subject = fresh.subject\n     and old.predicate = fresh.predicate\n     and coalesce(old.context, '') = coalesce(fresh.context, '')\n     and coalesce(old.object_normalized, old.object) <> coalesce(fresh.object_normalized, fresh.object)\n    where fresh.proposal_id = p_proposal_id\n      and fresh.predicate = any(public.wk_functional_predicates(fresh.space_id))\n      and fresh.status in ('verified', 'disputed')\n      and old.proposal_id is distinct from p_proposal_id\n      and old.status in ('verified', 'disputed')\n      and coalesce(fresh.valid_from, '-infinity'::timestamptz) < coalesce(old.valid_until, 'infinity'::timestamptz)\n      and coalesce(old.valid_from, '-infinity'::timestamptz) < coalesce(fresh.valid_until, 'infinity'::timestamptz)\n      and coalesce(fresh.agent_meta->>'adjudication', '') <> 'complementary'\n      and (fresh.supersedes_claim_id is null or fresh.supersedes_claim_id <> old.id)\n  )\n  update wk_claims\n  set status = 'disputed'\n  where status <> 'disputed'\n    and id in (select fresh_id from pairs union select old_id from pairs);\n  get diagnostics claims_disputed = row_count;\n\n  -- Flip 5b: ensure a 'contradicts' relation between the concepts carrying a\n  -- disputed pair. The DO UPDATE also CLEARS any pending removal marker (see\n  -- 0014 rationale: a re-derived contradiction supersedes a staged removal\n  -- of the same edge).\n  insert into wk_relations (space_id, from_concept_id, to_concept_id, kind, status, proposal_id)\n  select distinct fresh.space_id, fresh.concept_id, old.concept_id, 'contradicts', 'active', p_proposal_id\n  from wk_claims fresh\n  join wk_claims old\n    on old.space_id = fresh.space_id\n   and old.subject = fresh.subject\n   and old.predicate = fresh.predicate\n   and coalesce(old.context, '') = coalesce(fresh.context, '')\n   and coalesce(old.object_normalized, old.object) <> coalesce(fresh.object_normalized, fresh.object)\n  where fresh.proposal_id = p_proposal_id\n    and fresh.predicate = any(public.wk_functional_predicates(fresh.space_id))\n    and fresh.status = 'disputed'\n    and old.proposal_id is distinct from p_proposal_id\n    and old.status = 'disputed'\n    and coalesce(fresh.valid_from, '-infinity'::timestamptz) < coalesce(old.valid_until, 'infinity'::timestamptz)\n    and coalesce(old.valid_from, '-infinity'::timestamptz) < coalesce(fresh.valid_until, 'infinity'::timestamptz)\n    and coalesce(fresh.agent_meta->>'adjudication', '') <> 'complementary'\n    and (fresh.supersedes_claim_id is null or fresh.supersedes_claim_id <> old.id)\n    and fresh.concept_id <> old.concept_id\n  on conflict (space_id, from_concept_id, to_concept_id, kind)\n    do update set status = 'active', removal_proposal_id = null;\n\n  -- Flip 6: relations and decisions staged by this proposal → active.\n  update wk_relations\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  update wk_decisions\n  set status = 'active'\n  where proposal_id = p_proposal_id and status = 'proposed';\n\n  -- Flip 6b: relations MARKED for removal by this proposal → removed (0014).\n  update wk_relations\n  set status = 'removed'\n  where removal_proposal_id = p_proposal_id and status = 'active';\n  get diagnostics relations_removed_count = row_count;\n\n  -- Flip 7: the proposal itself, plus the space epoch (ETag driver).\n  update wk_change_proposals\n  set status = 'approved', reviewer = p_reviewer, review_note = p_note, reviewed_at = now()\n  where id = p_proposal_id;\n\n  update wk_spaces\n  set epoch = epoch + 1, updated_at = now()\n  where id = proposal.space_id;\n\n  select coalesce(array_agg(distinct c.slug), '{}')\n  into concept_slugs\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id;\n\n  -- Outbox events in the SAME transaction — the transactional-outbox\n  -- guarantee webhooks depend on.\n  insert into wk_outbox_events (space_id, event_type, payload)\n  values (\n    proposal.space_id,\n    'wikikit.proposal.approved',\n    jsonb_build_object(\n      'proposal_id', p_proposal_id,\n      'space', space_slug,\n      'reviewer', p_reviewer,\n      'note', p_note,\n      'concepts', to_jsonb(concept_slugs)\n    )\n  );\n\n  insert into wk_outbox_events (space_id, event_type, payload)\n  select proposal.space_id,\n         'wikikit.concept.updated',\n         jsonb_build_object('space', space_slug, 'slug', c.slug, 'rev', r.rev, 'proposal_id', p_proposal_id)\n  from wk_concept_revisions r\n  join wk_concepts c on c.id = r.concept_id\n  where r.proposal_id = p_proposal_id and r.status = 'current';\n\n  return jsonb_build_object(\n    'proposal_id', p_proposal_id,\n    'status', 'approved',\n    'concepts', to_jsonb(concept_slugs),\n    'claims_verified', claims_verified,\n    'claims_disputed', claims_disputed,\n    'claims_deprecated', claims_deprecated,\n    'relations_removed', relations_removed_count\n  );\nend;\n$$;\n",
  '0023_wk_space_refs':
    "-- Cross-space federation — qualified references, never knowledge copies.\n--\n--   * Spaces stay the tenancy and review boundary; federation links\n--     KNOWLEDGE across them: a relation may now point at a concept in\n--     another space ('mikebild-platform:contentkit'-style qualified slugs at\n--     the boundary), provided the target space is DECLARED in the source\n--     space's settings.imports and the staging principal can see both\n--     spaces.\n--   * to_space_id is a nullable denormalized column (null = intra-space, the\n--     overwhelmingly common row): to_concept_id is already a globally unique\n--     uuid, so the row shape supports foreign targets as-is — a second graph\n--     table would duplicate the entire staged/active/removed lifecycle\n--     machinery for no gain. wk_apply_proposal / wk_reject_proposal flip by\n--     proposal_id and need NO change.\n--   * Citations stay strictly intra-space (createProposal's tenant check is\n--     untouched): federation links knowledge, never provenance.\n--   * No backfill: every existing row is intra-space and NULL is that\n--     encoding.\nalter table public.wk_relations\n  add column if not exists to_space_id uuid references public.wk_spaces(id) on delete cascade;\n\ncreate index if not exists wk_relations_to_space_idx\n  on public.wk_relations (to_space_id)\n  where to_space_id is not null;\n",
  '0024_wk_oauth_identity_signup':
    "-- Per-identity permission ceiling for self-signup (WIKIKIT_OAUTH_ENABLE_SIGNUP).\n-- NULL means the identity is admitted through the provider allowlist and\n-- inherits the provider's allowed_scopes. A non-null array is the identity's\n-- own ceiling, written exactly once when an unknown identity self-registers\n-- at the minimal knowledge:read role. Allowlist logins reset the column to\n-- NULL so removing an allowlist entry keeps revoking access.\nalter table public.wk_oauth_identities\n  add column if not exists allowed_scopes text[];\n",
}

export const EMBEDDED_MIGRATIONS: EmbeddedMigration[] = EMBEDDED_JOURNAL.entries
  .slice()
  .sort((a, b) => a.idx - b.idx)
  .map((entry) => {
    const sql = SQL_BY_TAG[entry.tag]
    if (sql === undefined) throw new Error(`embedded migration missing SQL for ${entry.tag}`)
    const statements = sql
      .split('--> statement-breakpoint')
      .map((value) => value.trim())
      .filter(Boolean)
    return {
      idx: entry.idx,
      tag: entry.tag,
      when: entry.when,
      sql,
      hash: createHash('sha256').update(sql).digest('hex'),
      statements,
    }
  })
